import React, { useState } from 'react';
import { Facebook, Twitter, Check, X, Loader2, AlertCircle } from 'lucide-react';

interface LoginProps {
  onLogin: () => void;
}

declare global {
  interface Window {
    google: any;
  }
}

const GoogleIcon = () => (
  <svg width="16" height="16" viewBox="0 0 24 24" fill="currentColor" xmlns="http://www.w3.org/2000/svg">
    <path d="M12.48 10.92v3.28h7.84c-.24 1.84-.853 3.187-1.787 4.133-1.147 1.147-2.933 2.4-6.053 2.4-4.827 0-8.6-3.893-8.6-8.72s3.773-8.72 8.6-8.72c2.6 0 4.507 1.027 5.907 2.347l2.307-2.307C18.747 1.44 16.133 0 12.48 0 5.867 0 .533 5.347.533 12S5.867 24 12.48 24c3.44 0 6.013-1.133 8.053-3.24 2.067-2.067 2.72-5.027 2.72-7.533 0-.747-.067-1.48-.187-2.293h-10.587z" />
  </svg>
);

const Login: React.FC<LoginProps> = ({ onLogin }) => {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [remember, setRemember] = useState(false);
  const [isLoggingIn, setIsLoggingIn] = useState(false);

  // Validation State
  const [emailError, setEmailError] = useState('');
  const [passwordError, setPasswordError] = useState('');
  const [touched, setTouched] = useState({ email: false, password: false });

  // Forgot Password Modal State
  const [showForgotModal, setShowForgotModal] = useState(false);
  const [forgotEmail, setForgotEmail] = useState('');
  const [forgotEmailError, setForgotEmailError] = useState('');
  const [resetStatus, setResetStatus] = useState<'idle' | 'sending' | 'success' | 'error'>('idle');

  // Validation Logic
  const validateEmail = (val: string) => {
    if (!val) return 'Email is required';
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    if (!emailRegex.test(val)) return 'Please enter a valid email address';
    return '';
  };

  const validatePassword = (val: string) => {
    if (!val) return 'Password is required';
    if (val.length < 6) return 'Password must be at least 6 characters';
    return '';
  };

  const handleBlur = (field: 'email' | 'password') => {
    setTouched(prev => ({ ...prev, [field]: true }));
    if (field === 'email') setEmailError(validateEmail(email));
    if (field === 'password') setPasswordError(validatePassword(password));
  };

  const handleEmailChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    setEmail(e.target.value);
    // Real-time validation if already touched
    if (touched.email) setEmailError(validateEmail(e.target.value));
  };

  const handlePasswordChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    setPassword(e.target.value);
    // Real-time validation if already touched
    if (touched.password) setPasswordError(validatePassword(e.target.value));
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    // Validate all fields on submit
    const eErr = validateEmail(email);
    const pErr = validatePassword(password);

    setEmailError(eErr);
    setPasswordError(pErr);
    setTouched({ email: true, password: true });

    if (eErr || pErr) return;

    setIsLoggingIn(true);
    // Simulate login delay
    setTimeout(() => {
        onLogin();
    }, 500);
  };

  const handleForgotEmailChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    setForgotEmail(e.target.value);
    if (forgotEmailError) setForgotEmailError(validateEmail(e.target.value));
  };

  const handleForgotSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const err = validateEmail(forgotEmail);
    if (err) {
      setForgotEmailError(err);
      return; 
    }
    setForgotEmailError('');
    setResetStatus('sending');
    setTimeout(() => {
      setResetStatus('success');
    }, 1500);
  };

  const resetForgotState = () => {
    setShowForgotModal(false);
    setResetStatus('idle');
    setForgotEmail('');
    setForgotEmailError('');
  };

  const handleGoogleLogin = () => {
    setIsLoggingIn(true);

    // Check if Google Identity Services script is loaded
    if (window.google && window.google.accounts) {
      try {
        const client = window.google.accounts.oauth2.initTokenClient({
          client_id: process.env.GOOGLE_CLIENT_ID || 'MOCK_CLIENT_ID_FOR_DEMO',
          scope: 'email profile openid',
          callback: (tokenResponse: any) => {
            console.log("Google Login Success:", tokenResponse);
            onLogin();
          },
          error_callback: (error: any) => {
             console.error("Google Login Error:", error);
             if (process.env.GOOGLE_CLIENT_ID) {
                alert("Google Sign-in failed. Please check console.");
                setIsLoggingIn(false);
             } else {
                setTimeout(onLogin, 800);
             }
          }
        });

        client.requestAccessToken();

      } catch (error) {
        setTimeout(onLogin, 800);
      }
    } else {
      setTimeout(onLogin, 800);
    }
  };

  return (
    <div className="min-h-screen w-full flex items-center justify-center bg-[#f2f2f2] p-4 font-['Poppins']">

      {/* Forgot Password Modal */}
      {showForgotModal && (
        <div 
          className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm p-4 animate-in fade-in duration-200" 
          role="dialog" 
          aria-modal="true" 
          aria-labelledby="modal-title"
        >
          <div className="bg-white rounded-xl shadow-2xl w-full max-w-md p-8 relative">
            <button 
              onClick={resetForgotState}
              className="absolute top-4 right-4 text-slate-400 hover:text-slate-600 transition-colors"
              aria-label="Close modal"
            >
              <X size={20} />
            </button>

            <h3 id="modal-title" className="text-2xl font-bold text-slate-900 mb-2">Reset Password</h3>

            {resetStatus === 'success' ? (
              <div className="text-center py-6">
                <div className="w-16 h-16 bg-green-100 text-green-600 rounded-full flex items-center justify-center mx-auto mb-4">
                  <Check size={32} />
                </div>
                <h4 className="text-lg font-semibold text-slate-800 mb-2">Check your email</h4>
                <p className="text-slate-600 mb-6">We've sent a password reset link to <span className="font-semibold">{forgotEmail}</span></p>
                <button 
                  onClick={resetForgotState}
                  className="w-full bg-slate-900 text-white py-2 rounded-lg hover:bg-slate-800 transition-colors"
                >
                  Back to Login
                </button>
              </div>
            ) : (
              <form onSubmit={handleForgotSubmit}>
                <p className="text-slate-500 mb-6">Enter your email address and we'll send you a link to reset your password.</p>

                <div className="space-y-4">
                  <div>
                    <label htmlFor="reset-email" className="block text-sm font-medium text-slate-700 mb-1">Email Address</label>
                    <input 
                      id="reset-email"
                      type="email" 
                      value={forgotEmail}
                      onChange={handleForgotEmailChange}
                      placeholder="name@example.com"
                      className={`w-full p-3 border rounded-lg outline-none focus:ring-2 focus:ring-blue-500 focus:border-blue-500 transition-all
                        ${forgotEmailError ? 'border-red-500' : 'border-slate-300'}`}
                      autoFocus
                      aria-invalid={!!forgotEmailError}
                      aria-describedby={forgotEmailError ? "forgot-email-error" : undefined}
                    />
                    {forgotEmailError && (
                      <div id="forgot-email-error" className="flex items-center gap-1 text-red-500 text-xs mt-1 animate-in slide-in-from-top-1" role="alert">
                        <AlertCircle size={12} />
                        <span>{forgotEmailError}</span>
                      </div>
                    )}
                  </div>

                  <button 
                    type="submit"
                    disabled={resetStatus === 'sending'}
                    className="w-full bg-blue-600 hover:bg-blue-700 text-white font-medium py-3 rounded-lg transition-all shadow-md flex items-center justify-center gap-2 hover:shadow-lg transform active:scale-95 duration-200"
                  >
                    {resetStatus === 'sending' ? (
                      <>
                        <Loader2 size={18} className="animate-spin" />
                        Sending Link...
                      </>
                    ) : 'Send Reset Link'}
                  </button>
                </div>
              </form>
            )}
          </div>
        </div>
      )}

      {/* Main Login Card */}
      <div className="bg-white rounded-[20px] shadow-lg overflow-hidden w-full max-w-[900px] flex flex-col md:flex-row min-h-[600px]">

        {/* Left Side - Image (Reduced width to approx 40% (5/12) instead of 50% (1/2)) */}
        <div className="hidden md:block md:w-5/12 relative">
          <img 
            src="https://i.postimg.cc/sX5zbH5T/web_app_background_image_A.png" 
            alt="School workspace" 
            className="absolute inset-0 w-full h-full object-cover"
          />
          <div className="absolute inset-0 bg-blue-900/30 mix-blend-multiply"></div>
          <div className="absolute bottom-10 left-10 text-white p-6 z-10">
            <h2 className="text-3xl font-bold mb-2">AI School Hub</h2>
            <p className="text-white/90">Empowering educators with next-generation tools.</p>
          </div>
        </div>

        {/* Right Side - Form (Increased width to approx 60% (7/12)) */}
        <div className="w-full md:w-7/12 p-10 md:p-16 flex flex-col justify-center bg-white">
          <h2 className="text-3xl font-bold text-[#333] mb-10">Sign In</h2>

          <form onSubmit={handleSubmit} className="space-y-8" noValidate>
            <div className="group">
              <label htmlFor="email-input" className="block text-xs font-semibold text-slate-500 uppercase tracking-wider mb-1">Username or Email</label>
              <input 
                id="email-input"
                type="email" 
                value={email}
                onChange={handleEmailChange}
                onBlur={() => handleBlur('email')}
                placeholder="Your email address"
                className={`w-full border-b-2 py-2 text-[#333] placeholder-slate-400 outline-none transition-colors
                  ${emailError ? 'border-red-500 focus:border-red-500' : 'border-[#e5e7eb] focus:border-blue-600'}`}
                required
                aria-invalid={!!emailError}
                aria-describedby={emailError ? "email-error" : undefined}
              />
              {emailError && (
                <div id="email-error" className="flex items-center gap-1 text-red-500 text-xs mt-1 animate-in slide-in-from-top-1" role="alert">
                  <AlertCircle size={12} />
                  <span>{emailError}</span>
                </div>
              )}
            </div>

            <div className="group">
              <label htmlFor="password-input" className="block text-xs font-semibold text-slate-500 uppercase tracking-wider mb-1">Password</label>
              <input 
                id="password-input"
