              />
              {passwordError && (
                <div id="password-error" className="flex items-center gap-1 text-red-500 text-xs mt-1 animate-in slide-in-from-top-1" role="alert">
                  <AlertCircle size={12} />
                  <span>{passwordError}</span>
                </div>
              )}
            </div>

            <div className="flex items-center justify-between">
               <label className="flex items-center cursor-pointer relative group">
                 <input 
                    type="checkbox" 
                    checked={remember} 
                    onChange={(e) => setRemember(e.target.checked)}
                    className="sr-only peer"
                    id="remember-me"
                 />
                 <div className={`w-5 h-5 border-2 rounded transition-all flex items-center justify-center group-focus-within:ring-2 group-focus-within:ring-blue-200
                    ${remember ? 'bg-blue-600 border-blue-600' : 'border-slate-300 bg-transparent hover:border-slate-400'}`}>
                    {remember && <Check size={14} className="text-white" strokeWidth={3} />}
                 </div>
                 <span className="ml-2 text-sm text-slate-500 select-none">Remember me</span>
               </label>

               <button 
                 type="button" 
                 onClick={() => setShowForgotModal(true)}
                 className="text-sm text-slate-500 hover:text-blue-600 transition-colors focus:outline-none focus:underline"
               >
                 Forgot Password?
               </button>
            </div>

            <div className="pt-4">
              <button 
                type="submit"
                disabled={isLoggingIn}
                className="bg-blue-600 hover:bg-blue-700 text-white font-medium py-3 px-8 rounded-md transition-all shadow-md hover:shadow-lg w-auto inline-block disabled:opacity-70 disabled:cursor-not-allowed transform hover:-translate-y-0.5 active:translate-y-0 duration-200"
              >
                {isLoggingIn ? 'Signing in...' : 'Log in'}
