          <div className="mt-12">
            <p className="text-sm text-slate-500 mb-4">Or login with</p>
            <div className="flex gap-3 flex-wrap">
              <button className="flex items-center gap-2 px-4 py-2 text-sm font-medium text-white bg-[#3b5998] rounded hover:bg-[#2d4373] transition-all shadow-sm hover:shadow-md hover:-translate-y-1 duration-200 flex-1 justify-center min-w-[120px]">
