              <button className="flex items-center gap-2 px-4 py-2 text-sm font-medium text-white bg-[#1da1f2] rounded hover:bg-[#0c85d0] transition-all shadow-sm hover:shadow-md hover:-translate-y-1 duration-200 flex-1 justify-center min-w-[120px]">
