            <img 
              src="https://i.postimg.cc/B61fmVMV/IDSS_Logo_D1.png" 
              alt="IDSS Logo" 
              className="w-8 h-8 object-contain" 
            />
            <span>AI School Hub</span>
          </div>
          <button onClick={() => setSidebarOpen(false)} className="lg:hidden text-slate-400 hover:text-slate-600">
            <X size={20} />
          </button>
        </div>

        {/* Scrollable Navigation Area */}
        <div className="flex-1 overflow-y-auto custom-scrollbar">
          <div className="p-4">
            <button 
              onClick={() => setActiveTab('dashboard')}
              className="w-full flex items-center justify-center gap-2 bg-primary hover:bg-blue-700 text-white py-2.5 rounded-lg font-medium transition-all shadow-sm hover:shadow-md"
            >
              <PlusCircle size={18} />
              <span>New Resource</span>
            </button>
          </div>

          <nav className="flex flex-col gap-1 pb-4">
            <SidebarItem 
              icon={Layout} 
              label="Dashboard" 
              active={activeTab === 'dashboard'} 
              onClick={() => { setActiveTab('dashboard'); setCurrentPrompt(null); }} 
            />
            <div className="px-6 py-2 text-xs font-semibold text-slate-400 uppercase tracking-wider mt-4">Tools</div>
            {PROMPT_DEFINITIONS.map(def => {
              const Icon = icons[def.icon] || BookOpen;
              return (
                <SidebarItem 
                  key={def.id}
                  icon={Icon} 
                  label={def.title} 
                  active={currentPrompt?.id === def.id}
