```tsx
import React, { useState, useEffect, useRef } from 'react';
import { PromptDefinition, GeneratedContent, NarrativeData, EvaluationData, ChatMessage, UserProfile } from '../types';
import { streamContent, generateNarrativeAssets, evaluatePedagogy, sendChatFollowUp } from '../services/geminiService';
import { Loader2, Download, RefreshCw, ChevronRight, BarChart2, Image as ImageIcon, FileText, FileCode, MessageSquare, Send, User, Sparkles } from 'lucide-react';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, RadarChart, PolarGrid, PolarAngleAxis, PolarRadiusAxis, Radar } from 'recharts';

declare global {
  interface Window {
    html2pdf: any;
  }
}

interface EditorLayoutProps {
  prompt: PromptDefinition;
  user: UserProfile | null;
}

const EditorLayout: React.FC<EditorLayoutProps> = ({ prompt, user }) => {
  const [formData, setFormData] = useState<Record<string, string>>({});
  const [isGenerating, setIsGenerating] = useState(false);
  const [content, setContent] = useState('');
  const [narrative, setNarrative] = useState<NarrativeData | null>(null);
  const [evaluation, setEvaluation] = useState<EvaluationData | null>(null);
  const [activeView, setActiveView] = useState<'document' | 'narrative' | 'analytics' | 'chat'>('document');
  const [loadingExtras, setLoadingExtras] = useState(false);

  // Chat State
  const [chatMessages, setChatMessages] = useState<ChatMessage[]>([]);
  const [chatInput, setChatInput] = useState('');
  const [isChatSending, setIsChatSending] = useState(false);
  const chatEndRef = useRef<HTMLDivElement>(null);

  // Initialize form defaults
  useEffect(() => {
    const defaults: Record<string, string> = {};
    prompt.fields.forEach(f => {
      if (f.defaultValue) defaults[f.key] = f.defaultValue;
    });
    setFormData(defaults);
    setContent('');
    setNarrative(null);
    setEvaluation(null);
    setChatMessages([]); // Reset chat on new prompt
    setActiveView('document');
  }, [prompt]);

  // Scroll to bottom of chat
  useEffect(() => {
    if (activeView === 'chat') {
        chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
    }
  }, [chatMessages, activeView]);

  const handleInputChange = (key: string, value: string) => {
    setFormData(prev => ({ ...prev, [key]: value }));
  };

  const handleGenerate = async () => {
    setIsGenerating(true);
    setContent('');
    setNarrative(null);
    setEvaluation(null);
    setChatMessages([]); 

    // Construct Prompt
    let userPrompt = `Task: ${prompt.title}\n`;
    Object.entries(formData).forEach(([key, value]) => {
      const fieldLabel = prompt.fields.find(f => f.key === key)?.label || key;
      userPrompt += `${fieldLabel}: ${value}\n`;
    });

    try {
      await streamContent(
        'gemini-3-pro-preview', // Use a smart model for the main content
        prompt.systemInstruction,
        userPrompt,
        (chunk) => {
          setContent(prev => prev + chunk);
        }
      );
    } catch (e) {
      console.error("Generation error", e);
    } finally {
      setIsGenerating(false);
      // Trigger side-effects after main content is done
      generateExtras(content + (prompt.systemInstruction)); // Passing some context

      // Add initial greeting to chat
      setChatMessages([{
          id: 'init',
          role: 'model',
          text: 'I have generated your content based on the inputs. Feel free to ask me to refine specific sections, explain concepts, or add more details!',
          timestamp: Date.now()
      }]);
    }
  };

  const generateExtras = async (generatedText: string) => {
    if (!generatedText) return;
    setLoadingExtras(true);
    try {
      const [navData, evalData] = await Promise.all([
        generateNarrativeAssets(generatedText),
        evaluatePedagogy(generatedText)
      ]);
      setNarrative(navData);
      setEvaluation(evalData);
    } catch (e) {
      console.error("Extras generation error", e);
    } finally {
      setLoadingExtras(false);
    }
  };

  const handleChatSubmit = async (e: React.FormEvent) => {
      e.preventDefault();
      if (!chatInput.trim() || isChatSending) return;

      const userMsg: ChatMessage = {
          id: Date.now().toString(),
          role: 'user',
          text: chatInput,
          timestamp: Date.now()
      };

      setChatMessages(prev => [...prev, userMsg]);
      setChatInput('');
      setIsChatSending(true);

      try {
          // Convert internal chat format to simple history for service
          const history = chatMessages.map(m => ({ role: m.role, text: m.text }));

          const responseText = await sendChatFollowUp(
              'gemini-3-pro-preview',
              content,
              history,
              userMsg.text
          );

          const aiMsg: ChatMessage = {
              id: (Date.now() + 1).toString(),
              role: 'model',
              text: responseText,
              timestamp: Date.now()
          };

          setChatMessages(prev => [...prev, aiMsg]);
      } catch (err) {
          console.error("Chat error", err);
          const errorMsg: ChatMessage = {
            id: (Date.now() + 1).toString(),
            role: 'model',
            text: "I'm sorry, I encountered an error while processing your request. Please try again.",
            timestamp: Date.now()
        };
        setChatMessages(prev => [...prev, errorMsg]);
      } finally {
          setIsChatSending(false);
      }
  };

  const downloadFile = (fileContent: string, filename: string, type: string) => {
    const blob = new Blob([fileContent], { type });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = filename;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  const handleExportPDF = () => {
    const element = document.getElementById('document-preview');
    if (element && window.html2pdf) {
      const opt = {
        margin: 1,
        filename: `${prompt.title.toLowerCase().replace(/\s/g, '-')}.pdf`,
        image: { type: 'jpeg', quality: 0.98 },
        html2canvas: { scale: 2 },
        jsPDF: { unit: 'in', format: 'letter', orientation: 'portrait' }
      };
      window.html2pdf().set(opt).from(element).save();
    } else {
        window.print();
    }
  };

  const handleExportHTML = () => {
    if (!content) return;
    const fullHtml = `<!DOCTYPE html>
<html>
<head>
  <meta charset="utf-8">
  <title>${prompt.title}</title>
  <style>
    body { font-family: sans-serif; line-height: 1.6; max-width: 800px; margin: 2rem auto; padding: 0 1rem; color: #333; }
    h1, h2, h3 { color: #2563eb; }
  </style>
</head>
<body>
  <h1>${formData.topic || prompt.title}</h1>
  ${content}
</body>
</html>`;
    downloadFile(fullHtml, `${prompt.title.toLowerCase().replace(/\s/g, '-')}.html`, 'text/html');
  };

  const handleExportDOCX = () => {
    if (!content) return;
    // Word HTML Mime Type Hack
    const header = "<html xmlns:o='urn:schemas-microsoft-com:office:office' xmlns:w='urn:schemas-microsoft-com:office:word' xmlns='http://www.w3.org/TR/REC-html40'><head><meta charset='utf-8'><title>Export HTML To Doc</title></head><body>";
    const footer = "</body></html>";
    const sourceHTML = header + content + footer;
    downloadFile(sourceHTML, `${prompt.title.toLowerCase().replace(/\s/g, '-')}.doc`, 'application/vnd.ms-word');
  };

  return (
    <div className="flex h-full">
      {/* Configuration Panel */}
      <div className="w-1/3 min-w-[350px] max-w-[450px] bg-white border-r border-slate-200 flex flex-col h-full overflow-hidden">
        <div className="p-6 border-b border-slate-100">
          <h2 className="text-xl font-bold text-slate-900 flex items-center gap-2">
             Configure
          </h2>
          <p className="text-sm text-slate-500 mt-1">{prompt.description}</p>
        </div>

        <div className="flex-1 overflow-y-auto p-6 space-y-6">
          {prompt.fields.map((field) => (
            <div key={field.key} className="space-y-2">
              <label className="text-sm font-semibold text-slate-700 block">
                {field.label}
              </label>
              {field.type === 'select' ? (
                <div className="relative">
                  <select
                    className="w-full p-2.5 bg-slate-50 border border-slate-200 rounded-lg text-sm text-slate-700 focus:ring-2 focus:ring-primary/20 focus:border-primary outline-none appearance-none"
                    value={formData[field.key] || ''}
                    onChange={(e) => handleInputChange(field.key, e.target.value)}
                  >
                    <option value="" disabled>Select option</option>
                    {field.options?.map(opt => <option key={opt} value={opt}>{opt}</option>)}
                  </select>
                  <div className="absolute right-3 top-3 pointer-events-none text-slate-400">
                    <ChevronRight className="rotate-90" size={16} />
                  </div>
                </div>
              ) : field.type === 'textarea' ? (
                <textarea
                  className="w-full p-3 bg-slate-50 border border-slate-200 rounded-lg text-sm text-slate-700 focus:ring-2 focus:ring-primary/20 focus:border-primary outline-none min-h-[120px] resize-none"
                  placeholder={field.placeholder}
                  value={formData[field.key] || ''}
                  onChange={(e) => handleInputChange(field.key, e.target.value)}
                />
              ) : (
                <input
                  type={field.type}
                  className="w-full p-2.5 bg-slate-50 border border-slate-200 rounded-lg text-sm text-slate-700 focus:ring-2 focus:ring-primary/20 focus:border-primary outline-none"
                  placeholder={field.placeholder}
                  value={formData[field.key] || ''}
                  onChange={(e) => handleInputChange(field.key, e.target.value)}
                />
              )}
            </div>
          ))}
        </div>

        <div className="p-6 border-t border-slate-100 bg-slate-50">
          <button
            onClick={handleGenerate}
            disabled={isGenerating}
            className={`w-full py-3 px-4 rounded-xl flex items-center justify-center gap-2 font-semibold text-white transition-all shadow-md hover:shadow-lg
              ${isGenerating ? 'bg-primary/80 cursor-not-allowed shadow-inner' : 'bg-primary hover:bg-blue-600'}`}
          >
            {isGenerating ? <Loader2 className="animate-spin" /> : <RefreshCw />}
            {isGenerating ? 'Generating...' : 'Generate Content'}
          </button>
        </div>
      </div>

      {/* Preview Panel */}
      <div className="flex-1 bg-slate-100/50 flex flex-col h-full overflow-hidden">
        {/* Toolbar */}
        <div className="h-16 border-b border-slate-200 bg-white flex items-center justify-between px-6 shadow-sm z-10">
          <div className="flex bg-slate-100 p-1 rounded-lg">
            {[
              { id: 'document', label: 'Document', icon: FileText },
              { id: 'narrative', label: 'Narrative', icon: ImageIcon },
              { id: 'analytics', label: 'Analytics', icon: BarChart2 },
              { id: 'chat', label: 'AI Assistant', icon: MessageSquare }
            ].map((tab) => (
              <button
                key={tab.id}
                onClick={() => setActiveView(tab.id as any)}
                className={`px-3 py-1.5 rounded-md text-sm font-medium flex items-center gap-2 transition-all
                  ${activeView === tab.id ? 'bg-white text-slate-900 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
              >
                <tab.icon size={14} />
                {tab.label}
              </button>
            ))}
          </div>

          <div className="flex items-center gap-1">
             {loadingExtras && <span className="text-xs text-primary animate-pulse mr-3 font-medium">Processing Analytics...</span>}

             <div className="flex items-center bg-slate-50 rounded-lg border border-slate-200 p-0.5">
               <button onClick={handleExportHTML} disabled={!content} className="p-2 text-slate-500 hover:bg-white hover:text-orange-600 hover:shadow-sm rounded-md transition-all disabled:opacity-30" title="Export as HTML">
                 <FileCode size={18} />
               </button>
               <div className="w-px h-4 bg-slate-200 mx-0.5"></div>
               <button onClick={handleExportDOCX} disabled={!content} className="p-2 text-slate-500 hover:bg-white hover:text-blue-600 hover:shadow-sm rounded-md transition-all disabled:opacity-30" title="Export as DOCX (Word)">
                 <FileText size={18} />
               </button>
               <div className="w-px h-4 bg-slate-200 mx-0.5"></div>
               <button onClick={handleExportPDF} disabled={!content} className="p-2 text-slate-500 hover:bg-white hover:text-red-600 hover:shadow-sm rounded-md transition-all disabled:opacity-30" title="Export as PDF">
                 <Download size={18} />
