```typescript
import { db, auth } from './firebase';
import { collection, addDoc, query, where, getDocs, orderBy, serverTimestamp } from 'firebase/firestore';
import { GeneratedContent } from '../types';

export const saveGeneratedContent = async (userId: string, content: Partial<GeneratedContent>) => {
  // Simple check to see if db is a valid object before using SDK methods
  if (!db || Object.keys(db).length === 0) {
    console.warn("Firestore DB not initialized. Skipping save.");
    return null;
  }

  // Ensure user is authenticated in Firebase
  if (!auth.currentUser) {
    console.warn("No active Firebase session. Cannot save content to Firestore.");
    return null;
  }

  try {
    const docRef = await addDoc(collection(db, 'generated_content'), {
      ...content,
      userId,
      createdAt: serverTimestamp(),
    });
    console.log("Document written with ID: ", docRef.id);
    return docRef.id;
  } catch (e: any) {
    // Specifically log permission errors to help debugging
    if (e.code === 'permission-denied') {
        console.error("Firestore Permission Denied. Ensure the user is authenticated and rules allow writes.");
    } else {
        console.error("Error adding document: ", e);
    }
    // Don't throw, just log, so the UI doesn't break for the user
    return null; 
  }
};

export const getUserHistory = async (userId: string) => {
  if (!db || Object.keys(db).length === 0) {
    console.warn("Firestore DB not initialized. Skipping fetch.");
    return [];
  }

  try {
    const q = query(
      collection(db, 'generated_content'),
      where('userId', '==', userId),
      orderBy('createdAt', 'desc')
    );
    const querySnapshot = await getDocs(q);
    return querySnapshot.docs.map(doc => ({
      id: doc.id,
      ...doc.data()
    }));
  } catch (e) {
    console.error("Error fetching history: ", e);
    return [];
  }
};

