  }
};

export const getUserHistory = async (userId: string) => {
  if (!db || Object.keys(db).length === 0) return [];

  try {
    const q = query(
      collection(db, 'generated_content'),
      where('userId', '==', userId),
      orderBy('createdAt', 'desc')
    );
    const querySnapshot = await getDocs(q);
    return querySnapshot.docs.map(doc => ({
      id: doc.id,
      ...doc.data()
    }));
  } catch (e) {
    console.error("Error fetching history: ", e);
    return [];
  }
};

// --- TEMPLATE MANAGEMENT ---

export const saveTemplate = async (userId: string, template: Omit<SavedTemplate, 'id' | 'createdAt'>) => {
  if (!db || Object.keys(db).length === 0) {
    // Fallback to LocalStorage if DB not available
    const localTemplates = JSON.parse(localStorage.getItem('saved_templates') || '[]');
    const newTemplate = { ...template, id: Date.now().toString(), createdAt: Date.now() };
    localTemplates.push(newTemplate);
    localStorage.setItem('saved_templates', JSON.stringify(localTemplates));
    return newTemplate.id;
  }

  try {
    const docRef = await addDoc(collection(db, 'saved_templates'), {
      ...template,
      userId,
      createdAt: Date.now(), // Use client timestamp for simpler sorting in UI mixed with localStorage
    });
    return docRef.id;
  } catch (e) {
    console.error("Error saving template", e);
    return null;
  }
};

export const getTemplates = async (userId: string): Promise<SavedTemplate[]> => {
  let templates: SavedTemplate[] = [];

  // 1. Get LocalStorage Templates
  const local = JSON.parse(localStorage.getItem('saved_templates') || '[]');
  // Filter local templates belonging to this user (if we stored userId) or all if simple
  const userLocal = local.filter((t: any) => t.userId === userId);
  templates = [...userLocal];

  // 2. Get Firestore Templates
  if (db && Object.keys(db).length > 0 && auth.currentUser) {
    try {
      const q = query(collection(db, 'saved_templates'), where('userId', '==', userId));
      const snapshot = await getDocs(q);
      const cloudTemplates = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as SavedTemplate));
      templates = [...templates, ...cloudTemplates];
    } catch (e) {
      console.error("Error loading cloud templates", e);
    }
  }

  // Sort by created recent first
  return templates.sort((a, b) => b.createdAt - a.createdAt);
};

export const deleteTemplate = async (templateId: string) => {
   // Try local first
   const local = JSON.parse(localStorage.getItem('saved_templates') || '[]');
   const newLocal = local.filter((t: any) => t.id !== templateId);
   if (local.length !== newLocal.length) {
     localStorage.setItem('saved_templates', JSON.stringify(newLocal));
     return;
   }

   // Try cloud
   if (db && Object.keys(db).length > 0) {
     try {
       await deleteDoc(doc(db, 'saved_templates', templateId));
     } catch (e) {
       console.error("Error deleting cloud template", e);
     }
   }
};

// --- CHAT SESSION MANAGEMENT ---

export const saveChatSession = async (userId: string, promptId: string, messages: ChatMessage[]) => {
  const key = `chat_history_${userId}_${promptId}`;
  localStorage.setItem(key, JSON.stringify(messages));

  // Optional: Sync to Firestore for persistence across devices
  if (db && Object.keys(db).length > 0 && auth.currentUser) {
    try {
        // We use setDoc with merge to update the chat history for this specific prompt context
        // Using a composite ID for the document
        const docId = `${userId}_${promptId}`; 
        await setDoc(doc(collection(db, 'chat_sessions'), docId), {
            userId,
            promptId,
            messages,
            lastUpdated: serverTimestamp()
        }, { merge: true });
    } catch(e) {
        // Silent fail on cloud sync is fine, local is primary for speed
        console.warn("Cloud chat sync failed", e);
    }
  }
};

export const getChatSession = async (userId: string, promptId: string): Promise<ChatMessage[]> => {
  const key = `chat_history_${userId}_${promptId}`;
  const local = localStorage.getItem(key);

  if (local) {
      return JSON.parse(local);
  }

  // If not local, try cloud
  if (db && Object.keys(db).length > 0 && auth.currentUser) {
      try {
        const docId = `${userId}_${promptId}`;
        const docSnap = await getDoc(doc(db, 'chat_sessions', docId));
        if (docSnap.exists()) {
            return docSnap.data().messages as ChatMessage[];
        }
      } catch (e) {
          console.error("Error fetching cloud chat", e);
      }
  }

  return [];
};

import { GoogleGenAI, Type } from "@google/genai";
import { EvaluationData, NarrativeData } from "../types";

// Initialize the Google GenAI SDK
// API Key must be set in your environment variables (e.g. .env.local)
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

/**
 * Streams content generation for the main document editor.
 * Uses gemini-3-pro-preview by default for complex reasoning.
 */
export const streamContent = async (
  modelName: string,
  systemInstruction: string,
  userPrompt: string,
  onChunk: (text: string) => void
) => {
  try {
    const chat = ai.chats.create({
      model: modelName,
      config: {
        systemInstruction: systemInstruction,
        // Note: For gemini-3-pro-preview (thinking model), do NOT set thinkingBudget to 0.
        // Leaving it undefined allows the model to use its default thinking behavior.
      },
    });

    const result = await chat.sendMessageStream({ message: userPrompt });

    for await (const chunk of result) {
      if (chunk.text) {
        onChunk(chunk.text);
      }
    }
  } catch (error) {
    console.error("Error streaming content:", error);
    throw error;
  }
};

/**
 * Handles follow-up chat messages that are context-aware of the generated content.
 * Reconstructs the conversation history for stateless interaction.
 */
export const sendChatFollowUp = async (
  modelName: string,
  contextContent: string,
  history: { role: 'user' | 'model', text: string }[],
  newMessage: string
): Promise<string> => {
  try {
    // We construct a chat session that knows about the document context
    // Ideally, we would persist the 'chat' object, but for this stateless service architecture,
    // we recreate the context in the system instruction and pass previous history.

    const chat = ai.chats.create({
      model: modelName,
      config: {
        systemInstruction: `You are a highly capable AI educational consultant and writing assistant. 

        The user has generated the following educational content: 
        ---
        ${contextContent.substring(0, 25000)}
        ---

        Your goal is to help the user refine, expand, or understand this content.

        GUIDELINES FOR RESPONSE:
        1. **Depth & Detail**: Provide comprehensive, thoughtful answers. Do not be brief unless asked. Explain your reasoning.
        2. **Context Awareness**: Reference specific parts of the content above in your answers.
        3. **Professional Tone**: Maintain an academic or professional tone suitable for educators.
        4. **Structure**: Use paragraphs, lists, and clear spacing to make your response readable.

        STRICT FORMATTING RULE:
        Output purely in plain text. Do NOT use Markdown (no **, #, []) or HTML tags. 
        Format your response as if writing a standard professional email or document using only spacing and capitalization for structure.`
      },
      history: history.map(h => ({
        role: h.role,
        parts: [{ text: h.text }]
      }))
    });

    const result = await chat.sendMessage({ message: newMessage });
    return result.text || "I couldn't generate a response.";
  } catch (error) {
    console.error("Chat follow-up error:", error);
    throw error;
  }
};

/**
 * Generates an executive summary and a visual illustration for the content.
 * Uses gemini-2.5-flash for text summary and gemini-2.5-flash-image for image generation.
 */
export const generateNarrativeAssets = async (content: string): Promise<NarrativeData> => {
  // 1. Generate Summary and Key Takeaways
  const summaryResponse = await ai.models.generateContent({
    model: 'gemini-2.5-flash',
    contents: `Analyze the following educational content and provide a brief executive summary (max 3 sentences) and 3-5 key takeaways.

    Content:
    ${content.substring(0, 15000)}`, // Truncate to save tokens if extremely long
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          summary: { type: Type.STRING },
          keyTakeaways: {
            type: Type.ARRAY,
            items: { type: Type.STRING }
          }
        },
        required: ["summary", "keyTakeaways"]
      }
    }
  });

  const textData = JSON.parse(summaryResponse.text || '{}');

  // 2. Generate Illustration using Gemini Image capabilities
  // Create a visual prompt based on the summary
  const imagePrompt = `Create a high-quality, modern, flat-design educational illustration that visually represents this concept: "${textData.summary}". 
  Style: Professional vector art, clean lines, vibrant but professional colors (blues, teals, oranges). 
  Context: Suitable for a school presentation, textbook, or educational material. Minimalist and clear. No text in the image.`;

  let imageUrl = undefined;
  try {
     const imageResponse = await ai.models.generateContent({
        model: 'gemini-2.5-flash-image',
        contents: { parts: [{ text: imagePrompt }] },
        config: {
            imageConfig: {
                aspectRatio: "16:9",
            }
        }
     });

     // Extract image from response
     for (const part of imageResponse.candidates?.[0]?.content?.parts || []) {
        if (part.inlineData) {
            imageUrl = `data:image/png;base64,${part.inlineData.data}`;
            break;
        }
     }
  } catch (e) {
      console.warn("Image generation failed", e);
      // We don't throw here to ensure the summary is still returned even if the image fails
  }

  return {
    summary: textData.summary || "No summary available.",
    keyTakeaways: textData.keyTakeaways || [],
    imageUrl
  };
};

/**
 * Evaluates the pedagogical quality of the content.
 * Returns structured data including scores and feedback.
 */
export const evaluatePedagogy = async (content: string): Promise<EvaluationData> => {
    const response = await ai.models.generateContent({
        model: 'gemini-2.5-flash',
        contents: `Evaluate the following educational content based on pedagogical standards.
        Provide scores from 0 to 100 for Clarity, Relevance, Engagement, and Inclusivity.
        Provide a brief feedback paragraph and a list of specific improvement suggestions.

        Content:
        ${content.substring(0, 15000)}`,
        config: {
            responseMimeType: "application/json",
            responseSchema: {
                type: Type.OBJECT,
                properties: {
                    scores: {
                        type: Type.OBJECT,
                        properties: {
                            clarity: { type: Type.INTEGER },
                            relevance: { type: Type.INTEGER },
                            engagement: { type: Type.INTEGER },
                            inclusivity: { type: Type.INTEGER }
                        }
                    },
                    feedback: { type: Type.STRING },
                    suggestions: {
                        type: Type.ARRAY,
                        items: { type: Type.STRING }
                    }
                }
            }
        }
    });

    return JSON.parse(response.text || '{}');
};

import React, { useState, useEffect } from 'react';
import { PromptDefinition, NarrativeData, EvaluationData, ChatMessage, UserProfile, ContentType } from '../types';
import { streamContent, generateNarrativeAssets, evaluatePedagogy, sendChatFollowUp } from '../services/geminiService';
import { saveGeneratedContent, saveTemplate, saveChatSession, getChatSession } from '../services/contentService';
import { useToast } from '../context/ToastContext';
import { Download, FileText, FileCode, MessageSquare, BarChart2, Image as ImageIcon, Layout, Eye, Save, ChevronDown, FileType } from 'lucide-react';

import FormPanel from './editor/FormPanel';
import PreviewPanel from './editor/PreviewPanel';
import ChatPanel from './editor/ChatPanel';

// Declare html2pdf for TypeScript
declare var html2pdf: any;

interface EditorLayoutProps {
  prompt: PromptDefinition;
  user: UserProfile | null;
  initialFormData?: Record<string, string>; // Add support for loading templates
}

const EditorLayout: React.FC<EditorLayoutProps> = ({ prompt, user, initialFormData }) => {
  const { addToast } = useToast();

  // State
  const [formData, setFormData] = useState<Record<string, string>>({});
  const [isGenerating, setIsGenerating] = useState(false);
  const [content, setContent] = useState('');
  const [narrative, setNarrative] = useState<NarrativeData | null>(null);
  const [evaluation, setEvaluation] = useState<EvaluationData | null>(null);
  const [activeView, setActiveView] = useState<'document' | 'narrative' | 'analytics' | 'chat'>('document');
  const [loadingExtras, setLoadingExtras] = useState(false);

  // Chat State
  const [chatMessages, setChatMessages] = useState<ChatMessage[]>([]);
  const [isChatSending, setIsChatSending] = useState(false);

  // UI State
  const [showExportMenu, setShowExportMenu] = useState(false);
  const [showSaveTemplateModal, setShowSaveTemplateModal] = useState(false);
  const [templateName, setTemplateName] = useState('');

  // Initialize form defaults
  useEffect(() => {
    const defaults: Record<string, string> = {};
    if (initialFormData) {
        setFormData(initialFormData);
    } else {
        prompt.fields.forEach(f => {
            if (f.defaultValue) defaults[f.key] = f.defaultValue;
        });
        setFormData(defaults);
    }

    // Reset View
    setContent('');
    setNarrative(null);
    setEvaluation(null);
    setActiveView('document');

    // Load existing chat history for this prompt context if it exists
    if (user) {
        getChatSession(user.email, prompt.id).then(msgs => {
            if (msgs.length > 0) setChatMessages(msgs);
            else setChatMessages([]);
        });
    } else {
        setChatMessages([]);
    }
  }, [prompt, initialFormData, user]);

  const handleInputChange = (key: string, value: string) => {
    setFormData(prev => ({ ...prev, [key]: value }));
  };

  const handleGenerate = async () => {
    setIsGenerating(true);
    setContent('');
    setNarrative(null);
    setEvaluation(null);
    setActiveView('document');

    let userPrompt = `Task: ${prompt.title}\n`;
    Object.entries(formData).forEach(([key, value]) => {
      const fieldLabel = prompt.fields.find(f => f.key === key)?.label || key;
      userPrompt += `${fieldLabel}: ${value}\n`;
    });

    let fullContent = '';

    try {
      addToast('Generating content...', 'info');
      await streamContent(
        'gemini-3-pro-preview', 
        prompt.systemInstruction,
        userPrompt,
        (chunk) => {
          setContent(prev => prev + chunk);
          fullContent += chunk;
        }
      );

      // Auto-save to Firebase if user is logged in
      if (user) {
        try {
          await saveGeneratedContent(user.email, {
             type: prompt.title as unknown as ContentType, 
             title: formData['topic'] || formData['event_name'] || prompt.title,
             content: fullContent,
             metadata: formData
          });
        } catch (e) {
          console.error("Failed to auto-save", e);
        }
      }

      // Generate extras
      generateExtras(fullContent);

    } catch (error) {
      console.error("Generation error:", error);
      addToast("Failed to generate content. Please try again.", 'error');
    } finally {
      setIsGenerating(false);
    }
  };

  const generateExtras = async (text: string) => {
    setLoadingExtras(true);
    try {
      // Parallel execution for efficiency
      const [narrativeResult, evaluationResult] = await Promise.all([
        generateNarrativeAssets(text),
        evaluatePedagogy(text)
      ]);
      setNarrative(narrativeResult);
      setEvaluation(evaluationResult);
    } catch (e) {
      console.error("Error generating extras:", e);
    } finally {
      setLoadingExtras(false);
    }
  };

  const handleSendMessage = async (e: React.FormEvent, input: string) => {
    e.preventDefault();
    if (!input.trim()) return;

    const newMessage: ChatMessage = {
      id: Date.now().toString(),
      role: 'user',
      text: input,
      timestamp: Date.now()
    };

    const updatedMessages = [...chatMessages, newMessage];
    setChatMessages(updatedMessages);
    setIsChatSending(true);

    // Save chat session immediately
    if (user) saveChatSession(user.email, prompt.id, updatedMessages);

    try {
      const responseText = await sendChatFollowUp(
        'gemini-2.5-flash',
        content,
        updatedMessages.map(m => ({ role: m.role, text: m.text })),
        input
      );

      const aiMessage: ChatMessage = {
        id: (Date.now() + 1).toString(),
        role: 'model',
        text: responseText,
        timestamp: Date.now()
      };

      const finalMessages = [...updatedMessages, aiMessage];
      setChatMessages(finalMessages);
      if (user) saveChatSession(user.email, prompt.id, finalMessages);

    } catch (error) {
      addToast("Failed to send message.", 'error');
    } finally {
      setIsChatSending(false);
    }
  };

  // --- SAVE TEMPLATE HANDLER ---
  const handleSaveTemplate = async () => {
      if (!user) {
          addToast("Please login to save templates", "warning");
          return;
      }
      if (!templateName.trim()) {
          addToast("Please enter a template name", "warning");
          return;
      }

      const id = await saveTemplate(user.email, {
          userId: user.email,
          name: templateName,
          promptId: prompt.id,
          formData: formData
      });

      if (id) {
          addToast("Template saved successfully!", "success");
          setShowSaveTemplateModal(false);
          setTemplateName('');
          // Trigger a global event or context update in a real app to refresh sidebar
          window.dispatchEvent(new Event('templateSaved'));
      } else {
          addToast("Failed to save template", "error");
      }
  };

  // --- EXPORT HANDLERS ---
  const handleExport = (format: 'pdf' | 'txt' | 'md') => {
      if (!content) {
          addToast("No content to export", "warning");
          return;
      }

      const filename = `${formData['topic'] || 'Document'}_${Date.now()}`;

      if (format === 'pdf') {
          const element = document.getElementById('document-preview-content');
          if (!element) return;
          const opt = {
              margin: [0.5, 0.5],
              filename: `${filename}.pdf`,
              image: { type: 'jpeg', quality: 0.98 },
              html2canvas: { scale: 2 },
              jsPDF: { unit: 'in', format: 'letter', orientation: 'portrait' }
          };
          html2pdf().set(opt).from(element).save();
          addToast("Downloading PDF...", "success");
      } else if (format === 'txt') {
          // Strip HTML tags
          const tempDiv = document.createElement("div");
          tempDiv.innerHTML = content.replace(/<br\s*\/?>/gi, '\n').replace(/<\/p>/gi, '\n\n');
          const text = tempDiv.textContent || tempDiv.innerText || "";

          const blob = new Blob([text], { type: 'text/plain' });
          const url = URL.createObjectURL(blob);
          const a = document.createElement('a');
          a.href = url;
          a.download = `${filename}.txt`;
          a.click();
          URL.revokeObjectURL(url);
          addToast("Downloading Text file...", "success");
      } else if (format === 'md') {
          // Basic HTML to Markdown
          let md = content
            .replace(/<h1>(.*?)<\/h1>/gim, '# $1\n')
            .replace(/<h2>(.*?)<\/h2>/gim, '## $1\n')
            .replace(/<h3>(.*?)<\/h3>/gim, '### $1\n')
            .replace(/<b>(.*?)<\/b>/gim, '**$1**')
            .replace(/<strong>(.*?)<\/strong>/gim, '**$1**')
            .replace(/<i>(.*?)<\/i>/gim, '*$1*')
            .replace(/<br\s*\/?>/gim, '\n')
            .replace(/<p>(.*?)<\/p>/gim, '$1\n\n')
            .replace(/<li>(.*?)<\/li>/gim, '- $1\n')
            .replace(/<ul>/gim, '')
            .replace(/<\/ul>/gim, '\n')
            .replace(/<[^>]*>/g, ''); // strip remaining tags

           const blob = new Blob([md], { type: 'text/markdown' });
           const url = URL.createObjectURL(blob);
           const a = document.createElement('a');
           a.href = url;
           a.download = `${filename}.md`;
           a.click();
           URL.revokeObjectURL(url);
           addToast("Downloading Markdown...", "success");
      }
      setShowExportMenu(false);
  };

  return (
    <div className="flex h-full overflow-hidden relative">
      {/* Save Template Modal */}
      {showSaveTemplateModal && (
          <div className="absolute inset-0 z-50 bg-black/50 backdrop-blur-sm flex items-center justify-center p-4">
              <div className="bg-white rounded-xl shadow-xl p-6 w-full max-w-sm animate-in zoom-in-95 duration-200">
                  <h3 className="text-lg font-bold mb-4">Save Configuration</h3>
                  <p className="text-sm text-slate-500 mb-4">Save your current form inputs as a template to reuse later.</p>
                  <input 
                    type="text" 
                    placeholder="Template Name (e.g. 8th Grade History)" 
                    className="w-full p-3 border border-slate-300 rounded-lg mb-4 outline-none focus:ring-2 focus:ring-primary"
                    value={templateName}
                    onChange={e => setTemplateName(e.target.value)}
                    autoFocus
                  />
                  <div className="flex justify-end gap-2">
                      <button onClick={() => setShowSaveTemplateModal(false)} className="px-4 py-2 text-slate-600 hover:bg-slate-100 rounded-lg">Cancel</button>
                      <button onClick={handleSaveTemplate} className="px-4 py-2 bg-primary text-white rounded-lg hover:bg-blue-600">Save</button>
                  </div>
              </div>
          </div>
      )}

      {/* Left Panel - Form */}
      <FormPanel 
        prompt={prompt} 
        formData={formData} 
        onInputChange={handleInputChange} 
        onGenerate={handleGenerate}
        isGenerating={isGenerating}
        onSaveTemplate={() => setShowSaveTemplateModal(true)}
      />

      {/* Right Panel - Output */}
      <div className="flex-1 flex flex-col bg-slate-100 overflow-hidden relative">
        {/* Toolbar */}
        <div className="bg-white border-b border-slate-200 p-2 flex items-center justify-between shadow-sm z-10">
          <div className="flex gap-1 bg-slate-100 p-1 rounded-lg">
             <button 
               onClick={() => setActiveView('document')}
               className={`flex items-center gap-2 px-3 py-1.5 text-sm font-medium rounded-md transition-all
                 ${activeView === 'document' ? 'bg-white text-slate-900 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
             >
               <FileText size={16} /> Document
             </button>
             <button 
               onClick={() => setActiveView('narrative')}
               className={`flex items-center gap-2 px-3 py-1.5 text-sm font-medium rounded-md transition-all
                 ${activeView === 'narrative' ? 'bg-white text-slate-900 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
             >
               <ImageIcon size={16} /> Visuals
             </button>
             <button 
               onClick={() => setActiveView('analytics')}
               className={`flex items-center gap-2 px-3 py-1.5 text-sm font-medium rounded-md transition-all
                 ${activeView === 'analytics' ? 'bg-white text-slate-900 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
             >
               <BarChart2 size={16} /> Analytics
             </button>
             <button 
               onClick={() => setActiveView('chat')}
               className={`flex items-center gap-2 px-3 py-1.5 text-sm font-medium rounded-md transition-all
                 ${activeView === 'chat' ? 'bg-white text-slate-900 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
             >
               <MessageSquare size={16} /> Chat
             </button>
          </div>

          <div className="relative">
            <button 
                onClick={() => setShowExportMenu(!showExportMenu)}
                className="flex items-center gap-2 px-3 py-1.5 text-sm font-medium text-primary hover:bg-blue-50 rounded-md transition-colors"
            >
                <Download size={16} /> Export <ChevronDown size={14}/>
            </button>
            {showExportMenu && (
                <div className="absolute right-0 top-full mt-2 w-48 bg-white rounded-xl shadow-xl border border-slate-100 overflow-hidden z-50 animate-in slide-in-from-top-2">
                    <button onClick={() => handleExport('pdf')} className="w-full text-left px-4 py-3 hover:bg-slate-50 flex items-center gap-2 text-sm text-slate-700">
                        <FileText size={16} className="text-red-500"/> PDF Document
                    </button>
                    <button onClick={() => handleExport('txt')} className="w-full text-left px-4 py-3 hover:bg-slate-50 flex items-center gap-2 text-sm text-slate-700">
                        <FileType size={16} className="text-slate-500"/> Plain Text (.txt)
                    </button>
                    <button onClick={() => handleExport('md')} className="w-full text-left px-4 py-3 hover:bg-slate-50 flex items-center gap-2 text-sm text-slate-700">
                        <FileCode size={16} className="text-slate-900"/> Markdown (.md)
                    </button>
                </div>
            )}
          </div>
        </div>

        {/* Content Area */}
        <div className="flex-1 overflow-hidden relative">
           {activeView === 'chat' ? (
             <ChatPanel 
               messages={chatMessages} 
               onSendMessage={handleSendMessage} 
               isSending={isChatSending} 
               user={user}
             />
           ) : (
             <div className="h-full overflow-y-auto custom-scrollbar">
                <PreviewPanel 
                  activeView={activeView}
                  content={content}
                  narrative={narrative}
                  evaluation={evaluation}
                  loadingExtras={loadingExtras}
                  isGenerating={isGenerating}
                  prompt={prompt}
                  formData={formData}
                  onContentUpdate={(newContent) => setContent(newContent)}
                />
             </div>
           )}
        </div>
      </div>
    </div>
  );
};

