import { db, auth } from './firebase';
import { 
  collection, 
  addDoc, 
  serverTimestamp, 
  query, 
  where, 
  orderBy, 
  getDocs, 
  doc, 
  deleteDoc, 
  setDoc,
  getDoc
} from 'firebase/firestore';
import { GeneratedContent, SavedTemplate, ChatMessage } from '../types';

// --- CONTENT MANAGEMENT ---

export const saveGeneratedContent = async (userId: string, content: Partial<GeneratedContent>) => {
  if (!db || !auth.currentUser) return null;

  try {
    const docRef = await addDoc(collection(db, 'generated_content'), {
      ...content,
      userId,
      createdAt: serverTimestamp(),
    });
    return docRef.id;
  } catch (e: any) {
    console.error("Error adding document: ", e);
    return null; 
  }
};

export const getUserHistory = async (userId: string) => {
  if (!db) return [];

  try {
    const q = query(
      collection(db, 'generated_content'),
      where('userId', '==', userId),
      orderBy('createdAt', 'desc')
    );

    const snapshot = await getDocs(q);

    return snapshot.docs.map((doc) => ({
      id: doc.id,
      ...doc.data()
    }));
  } catch (e) {
    console.error("Error fetching history: ", e);
    return [];
  }
};

// --- TEMPLATE MANAGEMENT ---

export const saveTemplate = async (userId: string, template: Omit<SavedTemplate, 'id' | 'createdAt'>) => {
  if (!db) {
    // Fallback to LocalStorage if DB not available
    const localTemplates = JSON.parse(localStorage.getItem('saved_templates') || '[]');
    const newTemplate = { ...template, id: Date.now().toString(), createdAt: Date.now() };
    localTemplates.push(newTemplate);
    localStorage.setItem('saved_templates', JSON.stringify(localTemplates));
    return newTemplate.id;
  }

  try {
    const docRef = await addDoc(collection(db, 'saved_templates'), {
      ...template,
      userId,
      createdAt: Date.now(), 
    });
    return docRef.id;
  } catch (e) {
    console.error("Error saving template", e);
    return null;
  }
};

export const getTemplates = async (userId: string): Promise<SavedTemplate[]> => {
  let templates: SavedTemplate[] = [];

  // 1. Get LocalStorage Templates
  const local = JSON.parse(localStorage.getItem('saved_templates') || '[]');
  const userLocal = local.filter((t: any) => t.userId === userId);
  templates = [...userLocal];

  // 2. Get Firestore Templates
  if (db && auth.currentUser) {
    try {
      const q = query(
        collection(db, 'saved_templates'),
        where('userId', '==', userId)
      );
      const snapshot = await getDocs(q);

      const cloudTemplates = snapshot.docs.map((doc) => ({ id: doc.id, ...doc.data() } as SavedTemplate));
      templates = [...templates, ...cloudTemplates];
    } catch (e) {
      console.error("Error loading cloud templates", e);
    }
  }

  // Sort by created recent first
  return templates.sort((a, b) => b.createdAt - a.createdAt);
};

export const deleteTemplate = async (templateId: string) => {
   // Try local first
   const local = JSON.parse(localStorage.getItem('saved_templates') || '[]');
   const newLocal = local.filter((t: any) => t.id !== templateId);
   if (local.length !== newLocal.length) {
     localStorage.setItem('saved_templates', JSON.stringify(newLocal));
     return;
   }

   // Try cloud
   if (db) {
     try {
       await deleteDoc(doc(db, 'saved_templates', templateId));
     } catch (e) {
       console.error("Error deleting cloud template", e);
     }
   }
};

// --- CHAT SESSION MANAGEMENT ---

export const saveChatSession = async (userId: string, promptId: string, messages: ChatMessage[]) => {
  const key = `chat_history_${userId}_${promptId}`;
  localStorage.setItem(key, JSON.stringify(messages));

  // Optional: Sync to Firestore for persistence across devices
  if (db && auth.currentUser) {
    try {
        const docId = `${userId}_${promptId}`; 
        const docRef = doc(db, 'chat_sessions', docId);
        await setDoc(docRef, {
            userId,
            promptId,
            messages,
            lastUpdated: serverTimestamp()
        }, { merge: true });
    } catch(e) {
        console.warn("Cloud chat sync failed", e);
    }
  }
};

export const getChatSession = async (userId: string, promptId: string): Promise<ChatMessage[]> => {
  const key = `chat_history_${userId}_${promptId}`;
  const local = localStorage.getItem(key);

  if (local) {
      return JSON.parse(local);
  }

  // If not local, try cloud
  if (db && auth.currentUser) {
      try {
        const docId = `${userId}_${promptId}`;
        const docRef = doc(db, 'chat_sessions', docId);
        const docSnap = await getDoc(docRef);
        if (docSnap.exists()) {
            return docSnap.data().messages as ChatMessage[];
        }
      } catch (e) {
          console.error("Error fetching cloud chat", e);
      }
  }

  return [];
};

