                                    <th className="p-3 font-semibold text-slate-500">Details</th>
                                    <th className="p-3 font-semibold text-slate-500 text-right">Time</th>
                                </tr>
                            </thead>
                            <tbody className="divide-y divide-slate-100">
                                {selectedUser.auditLogs?.map((log, i) => (
