             Refresh Data
           </button>
           <button className="px-4 py-2 bg-primary text-white rounded-lg hover:bg-blue-600 transition-colors text-sm font-medium flex items-center gap-2">
             <Download size={16} /> Export Report
           </button>
        </div>
      </div>

