                      autoFocus
                    />
                    {forgotEmailError && (
                      <div className="flex items-center gap-1 text-red-500 text-sm mt-2">
                        <AlertCircle size={16} />
                        <span>{forgotEmailError}</span>
                      </div>
                    )}
