                  <button 
                    type="submit"
                    disabled={resetStatus === 'sending'}
                    className="w-full bg-blue-600 hover:bg-blue-700 text-white text-lg font-medium py-4 rounded-lg transition-all shadow-md flex items-center justify-center gap-2"
