export default App;

import React, { useState, useEffect } from 'react';
import { PromptDefinition, NarrativeData, EvaluationData, UserProfile, ContentType } from '../types';
import { streamContent, generateNarrativeAssets, evaluatePedagogy } from '../services/geminiService';
import { saveGeneratedContent, saveTemplate } from '../services/contentService';
import { useToast } from '../context/ToastContext';
import { Download, FileText, FileCode, MessageSquare, BarChart2, Image as ImageIcon, ChevronDown, FileType, File, Save, Check, X } from 'lucide-react';
import { asBlob } from 'html-docx-js-typescript';

import FormPanel from './editor/FormPanel';
import PreviewPanel from './editor/PreviewPanel';
import ChatPanel from './editor/ChatPanel';

// Declare html2pdf for TypeScript
declare var html2pdf: any;

interface EditorLayoutProps {
  prompt: PromptDefinition;
  user: UserProfile | null;
  initialFormData?: Record<string, string>;
}

const EditorLayout: React.FC<EditorLayoutProps> = ({ prompt, user, initialFormData }) => {
  const { addToast } = useToast();

  // State
  const [formData, setFormData] = useState<Record<string, string>>({});
  const [isGenerating, setIsGenerating] = useState(false);
  const [content, setContent] = useState('');
  const [narrative, setNarrative] = useState<NarrativeData | null>(null);
  const [evaluation, setEvaluation] = useState<EvaluationData | null>(null);
  const [activeView, setActiveView] = useState<'document' | 'narrative' | 'analytics' | 'chat'>('document');
  const [loadingExtras, setLoadingExtras] = useState(false);

  // UI State
  const [showExportMenu, setShowExportMenu] = useState(false);
  const [showSaveTemplateModal, setShowSaveTemplateModal] = useState(false);
  const [templateName, setTemplateName] = useState('');

  // Initialize form defaults
  useEffect(() => {
    const defaults: Record<string, string> = {};
    if (initialFormData) {
        setFormData(initialFormData);
    } else {
        prompt.fields.forEach(f => {
            if (f.defaultValue) defaults[f.key] = f.defaultValue;
        });
        setFormData(defaults);
    }

    // Reset View
    setContent('');
    setNarrative(null);
    setEvaluation(null);
    setActiveView('document');
  }, [prompt, initialFormData, user]);

  const handleInputChange = (key: string, value: string) => {
    setFormData(prev => ({ ...prev, [key]: value }));
  };

  const handleGenerate = async () => {
    setIsGenerating(true);
    setContent('');
    setNarrative(null);
    setEvaluation(null);
    setActiveView('document');

    let userPrompt = `Task: ${prompt.title}\n`;
    Object.entries(formData).forEach(([key, value]) => {
      const fieldLabel = prompt.fields.find(f => f.key === key)?.label || key;
      userPrompt += `${fieldLabel}: ${value}\n`;
    });

    let fullContent = '';

    try {
      addToast('Generating content...', 'info');
      await streamContent(
        'gemini-3-pro-preview', 
        prompt.systemInstruction,
        userPrompt,
        (chunk) => {
          setContent(prev => prev + chunk);
          fullContent += chunk;
        }
      );

      // Auto-save to Firebase if user is logged in
      if (user) {
        try {
          await saveGeneratedContent(user.email, {
             type: prompt.title as unknown as ContentType, 
             title: formData['topic'] || formData['event_name'] || prompt.title,
             content: fullContent,
             metadata: formData
          });
        } catch (e) {
          console.error("Failed to auto-save", e);
        }
      }

      // Generate extras
      generateExtras(fullContent);

    } catch (error) {
      console.error("Generation error:", error);
      addToast("Failed to generate content. Please try again.", 'error');
    } finally {
      setIsGenerating(false);
    }
  };

  const generateExtras = async (text: string) => {
    setLoadingExtras(true);
    try {
      // Parallel execution for efficiency
      const [narrativeResult, evaluationResult] = await Promise.all([
        generateNarrativeAssets(text),
        evaluatePedagogy(text)
      ]);
      setNarrative(narrativeResult);
      setEvaluation(evaluationResult);
    } catch (e) {
      console.error("Error generating extras:", e);
    } finally {
      setLoadingExtras(false);
    }
  };

  // --- SAVE TEMPLATE HANDLER ---
  const handleSaveTemplate = async (e?: React.FormEvent) => {
      if (e) e.preventDefault();

      if (!user) {
          addToast("Please login to save templates", "warning");
          return;
      }
      if (!templateName.trim()) {
          addToast("Please enter a template name", "warning");
          return;
      }

      // NO window.confirm here. The Modal serves as the robust confirmation.
      const id = await saveTemplate(user.email, {
          userId: user.email,
          name: templateName,
          promptId: prompt.id,
          formData: formData
      });

      if (id) {
          addToast("Template saved successfully!", "success");
          setShowSaveTemplateModal(false);
          setTemplateName('');
          // Trigger event to update sidebar
          window.dispatchEvent(new Event('templateSaved'));
      } else {
          addToast("Failed to save template", "error");
      }
  };

  const downloadFile = (blob: Blob, filename: string) => {
      const url = URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = filename;
      a.click();
      URL.revokeObjectURL(url);
  };

  // --- EXPORT HANDLERS ---
  const handleExport = async (format: 'pdf' | 'txt' | 'md' | 'docx' | 'html') => {
      if (!content) {
          addToast("No content to export", "warning");
          return;
      }

      const filename = `${formData['topic'] || 'Document'}_${Date.now()}`;

      try {
        if (format === 'pdf') {
            const element = document.getElementById('document-preview-content');
            if (!element) return;
            const opt = {
                margin: [0.5, 0.5],
                filename: `${filename}.pdf`,
                image: { type: 'jpeg', quality: 0.98 },
                html2canvas: { scale: 2 },
                jsPDF: { unit: 'in', format: 'letter', orientation: 'portrait' }
            };
            html2pdf().set(opt).from(element).save();
            addToast("Downloading PDF...", "success");
        } else if (format === 'txt') {
            const tempDiv = document.createElement("div");
            tempDiv.innerHTML = content.replace(/<br\s*\/?>/gi, '\n').replace(/<\/p>/gi, '\n\n');
            const text = tempDiv.textContent || tempDiv.innerText || "";
            const blob = new Blob([text], { type: 'text/plain' });
            downloadFile(blob, `${filename}.txt`);
            addToast("Downloading Text file...", "success");
        } else if (format === 'md') {
            let md = content
              .replace(/<h1>(.*?)<\/h1>/gim, '# $1\n')
              .replace(/<h2>(.*?)<\/h2>/gim, '## $1\n')
              .replace(/<h3>(.*?)<\/h3>/gim, '### $1\n')
              .replace(/<b>(.*?)<\/b>/gim, '**$1**')
              .replace(/<strong>(.*?)<\/strong>/gim, '**$1**')
              .replace(/<i>(.*?)<\/i>/gim, '*$1*')
              .replace(/<br\s*\/?>/gim, '\n')
              .replace(/<p>(.*?)<\/p>/gim, '$1\n\n')
              .replace(/<li>(.*?)<\/li>/gim, '- $1\n')
              .replace(/<ul>/gim, '')
              .replace(/<\/ul>/gim, '\n')
              .replace(/<[^>]*>/g, ''); 
             const blob = new Blob([md], { type: 'text/markdown' });
             downloadFile(blob, `${filename}.md`);
             addToast("Downloading Markdown...", "success");
        } else if (format === 'docx') {
             const htmlString = `<!DOCTYPE html><html><head><meta charset="utf-8"><title>${filename}</title></head><body>${content}</body></html>`;
             const blob = await asBlob(htmlString);
             if (blob) {
                downloadFile(blob as Blob, `${filename}.docx`);
                addToast("Downloading DOCX...", "success");
             }
        } else if (format === 'html') {
             const blob = new Blob([content], { type: 'text/html' });
             downloadFile(blob, `${filename}.html`);
             addToast("Downloading HTML...", "success");
        }
      } catch (err) {
        console.error("Export error", err);
        addToast("Export failed. Please try again.", "error");
      }
      setShowExportMenu(false);
  };

  // Helper for view switcher button classes
  const getViewButtonClass = (viewName: string) => {
      const isActive = activeView === viewName;
      return `flex items-center gap-2 px-4 py-2 text-sm font-semibold rounded-lg transition-all border
        ${isActive 
            ? 'bg-primary text-white border-primary shadow-sm ring-2 ring-primary/20' 
            : 'bg-white text-slate-500 border-transparent hover:bg-slate-50 hover:text-slate-700'}`;
  };

  return (
    <div className="flex h-full overflow-hidden relative">
      {/* Save Template Modal */}
      {showSaveTemplateModal && (
          <div className="absolute inset-0 z-50 bg-black/60 backdrop-blur-sm flex items-center justify-center p-4">
              <div className="bg-white rounded-xl shadow-2xl p-0 w-full max-w-md animate-in zoom-in-95 duration-200 overflow-hidden">
                  <div className="bg-slate-50 border-b border-slate-100 p-6">
                     <h3 className="text-xl font-bold text-slate-900">Save Configuration</h3>
                     <p className="text-sm text-slate-500 mt-1">
                        Creating a template for <strong>{prompt.title}</strong>
                     </p>
                  </div>

                  <div className="p-6">
                      <p className="text-sm text-slate-600 mb-6 bg-blue-50 p-4 rounded-lg border border-blue-100 text-blue-800">
                          This will save the current <strong>{Object.keys(formData).length} fields</strong> as a reusable template. 
                          You can load it anytime from your profile menu.
                      </p>

                      <form onSubmit={handleSaveTemplate}>
                          <label className="block text-sm font-semibold text-slate-700 mb-2">Template Name</label>
                          <input 
                            type="text" 
                            placeholder="e.g., 'Grade 8 History - Unit 1'" 
                            className="w-full p-3 border border-slate-300 rounded-lg mb-6 outline-none focus:ring-2 focus:ring-primary focus:border-primary transition-all"
                            value={templateName}
                            onChange={e => setTemplateName(e.target.value)}
                            autoFocus
                          />
                          <div className="flex justify-end gap-3">
                              <button 
                                type="button" 
                                onClick={() => setShowSaveTemplateModal(false)} 
                                className="px-5 py-2.5 text-slate-600 hover:bg-slate-100 rounded-lg font-medium transition-colors"
                              >
                                Cancel
                              </button>
                              <button 
                                type="submit" 
                                className="px-5 py-2.5 bg-primary text-white rounded-lg hover:bg-blue-600 font-medium shadow-sm transition-colors flex items-center gap-2"
                              >
                                <Check size={18} />
                                Confirm Save
                              </button>
                          </div>
                      </form>
                  </div>
              </div>
          </div>
      )}

      {/* Left Panel - Form */}
      <FormPanel 
        prompt={prompt} 
        formData={formData} 
        onInputChange={handleInputChange} 
        onGenerate={handleGenerate}
        isGenerating={isGenerating}
        onSaveTemplate={() => setShowSaveTemplateModal(true)}
      />

      {/* Right Panel - Output */}
      <div className="flex-1 flex flex-col bg-slate-100 overflow-hidden relative">
        {/* Toolbar */}
        <div className="bg-white border-b border-slate-200 px-4 py-3 flex items-center justify-between shadow-sm z-10">
          <div className="flex gap-2 p-1 bg-slate-100 rounded-xl">
             <button 
               onClick={() => setActiveView('document')}
               className={getViewButtonClass('document')}
             >
               <FileText size={16} /> Document
             </button>
             <button 
               onClick={() => setActiveView('narrative')}
               className={getViewButtonClass('narrative')}
             >
               <ImageIcon size={16} /> Visuals
             </button>
             <button 
               onClick={() => setActiveView('analytics')}
               className={getViewButtonClass('analytics')}
             >
               <BarChart2 size={16} /> Analytics
             </button>
             <button 
               onClick={() => setActiveView('chat')}
               className={getViewButtonClass('chat')}
             >
               <MessageSquare size={16} /> Chat
             </button>
          </div>

          <div className="relative">
            <button 
                onClick={() => setShowExportMenu(!showExportMenu)}
                className={`flex items-center gap-2 px-4 py-2 text-sm font-semibold rounded-lg transition-colors border
                ${showExportMenu ? 'bg-blue-50 text-primary border-blue-200' : 'bg-white text-slate-600 border-slate-200 hover:bg-slate-50'}`}
            >
                <Download size={16} /> Export <ChevronDown size={14}/>
            </button>
            {showExportMenu && (
                <div className="absolute right-0 top-full mt-2 w-56 bg-white rounded-xl shadow-xl border border-slate-100 overflow-hidden z-50 animate-in slide-in-from-top-2">
                    <button onClick={() => handleExport('pdf')} className="w-full text-left px-4 py-3 hover:bg-slate-50 flex items-center gap-3 text-sm text-slate-700">
                        <FileText size={16} className="text-red-500"/> PDF Document
                    </button>
                    <button onClick={() => handleExport('docx')} className="w-full text-left px-4 py-3 hover:bg-slate-50 flex items-center gap-3 text-sm text-slate-700">
                        <FileText size={16} className="text-blue-600"/> Word Document (.docx)
                    </button>
                    <button onClick={() => handleExport('html')} className="w-full text-left px-4 py-3 hover:bg-slate-50 flex items-center gap-3 text-sm text-slate-700">
                        <FileCode size={16} className="text-orange-500"/> HTML File (.html)
                    </button>
                    <div className="h-px bg-slate-100 mx-4"></div>
                    <button onClick={() => handleExport('txt')} className="w-full text-left px-4 py-3 hover:bg-slate-50 flex items-center gap-3 text-sm text-slate-700">
                        <FileType size={16} className="text-slate-500"/> Plain Text (.txt)
                    </button>
                    <button onClick={() => handleExport('md')} className="w-full text-left px-4 py-3 hover:bg-slate-50 flex items-center gap-3 text-sm text-slate-700">
                        <File size={16} className="text-slate-900"/> Markdown (.md)
                    </button>
                </div>
            )}
          </div>
        </div>

        {/* Content Area */}
        <div className="flex-1 overflow-hidden relative">
           {activeView === 'chat' ? (
             <ChatPanel 
               promptId={prompt.id}
               userEmail={user?.email}
               user={user}
               contentContext={content}
             />
           ) : (
             <div className="h-full overflow-y-auto custom-scrollbar">
                <PreviewPanel 
                  activeView={activeView}
                  content={content}
                  narrative={narrative}
                  evaluation={evaluation}
                  loadingExtras={loadingExtras}
                  isGenerating={isGenerating}
                  prompt={prompt}
                  formData={formData}
                  onContentUpdate={(newContent) => setContent(newContent)}
                />
             </div>
           )}
        </div>
      </div>
    </div>
  );
};

export default EditorLayout;

import React, { useRef, useEffect, useState } from 'react';
import { ChatMessage, UserProfile } from '../../types';
import { Send, User, Sparkles, Loader2, Brain, UserCircle } from 'lucide-react';
import { sendChatFollowUp } from '../../services/geminiService';
import { saveChatSession, getChatSession } from '../../services/contentService';
import { useToast } from '../../context/ToastContext';

interface ChatPanelProps {
  promptId: string;
  userEmail: string | undefined;
  user: UserProfile | null;
  contentContext: string; // We need the content context for the AI to answer questions about it
}

const CHAT_SYSTEM_INSTRUCTION = `You are a highly capable AI educational consultant and writing assistant.

The user has generated educational content which is provided in the context.
Your goal is to help the user refine, expand, or understand this content.

GUIDELINES FOR RESPONSE:
1. **CLARITY & CONCISENESS**: Be direct, friendly, and efficient. Avoid unnecessary fluff or overly robotic pleasantries. Get straight to the pedagogical value.
2. **DEPTH & DETAIL**: While being concise, do not oversimplify complex topics. Provide detailed, evidence-based reasoning, specific examples, or actionable steps when the user asks for advice or revisions.
3. **CONTEXT AWARENESS**: Always reference the specific content provided in the context when answering.
4. **PROFESSIONAL TONE**: Maintain a supportive, academic, yet accessible tone suitable for professional educators.
5. **FORMATTING**: Use paragraphs, bullet points, and spacing to make your response easy to scan. Do NOT use Markdown code blocks or HTML tags; use standard text formatting.`;

const ChatPanel: React.FC<ChatPanelProps> = ({ promptId, userEmail, user, contentContext }) => {
  const { addToast } = useToast();
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [input, setInput] = useState('');
  const [isSending, setIsSending] = useState(false);
  const [isLoadingHistory, setIsLoadingHistory] = useState(false);
  const chatEndRef = useRef<HTMLDivElement>(null);

  // Load History on Mount or Prompt Change
  useEffect(() => {
    if (userEmail && promptId) {
      setIsLoadingHistory(true);
      getChatSession(userEmail, promptId)
        .then((msgs) => {
          setMessages(msgs || []);
        })
        .catch((err) => {
          console.error("Failed to load chat history", err);
        })
        .finally(() => {
          setIsLoadingHistory(false);
        });
    } else {
        setMessages([]);
    }
  }, [userEmail, promptId]);

  // Scroll to bottom on new messages
  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages, isSending]);

  const handleSendMessage = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim()) return;

    const userMessage: ChatMessage = {
      id: Date.now().toString(),
      role: 'user',
      text: input,
      timestamp: Date.now()
    };

    const updatedMessages = [...messages, userMessage];
    setMessages(updatedMessages);
    setInput('');
    setIsSending(true);

    // Auto-save user message to persistence layer
    if (userEmail) saveChatSession(userEmail, promptId, updatedMessages);

    try {
      // Send to Gemini
      // We use the accumulated messages as history for context
      const responseText = await sendChatFollowUp(
        'gemini-2.5-flash',
        contentContext,
        updatedMessages.map(m => ({ role: m.role, text: m.text })),
        userMessage.text,
        CHAT_SYSTEM_INSTRUCTION // Pass the custom instruction here
      );

      const aiMessage: ChatMessage = {
        id: (Date.now() + 1).toString(),
        role: 'model',
        text: responseText,
        timestamp: Date.now()
      };

      const finalMessages = [...updatedMessages, aiMessage];
      setMessages(finalMessages);

      // Auto-save AI message to persistence layer
      if (userEmail) saveChatSession(userEmail, promptId, finalMessages);

    } catch (error) {
      console.error(error);
      addToast("Failed to get response from AI.", 'error');
    } finally {
      setIsSending(false);
    }
  };

  return (
    <div className="flex flex-col h-full bg-slate-50 relative">
      {/* Chat History */}
      <div className="flex-1 overflow-y-auto p-4 space-y-8 bg-slate-50">
        {isLoadingHistory && (
            <div className="flex justify-center p-4">
                <Loader2 className="animate-spin text-slate-400" />
            </div>
        )}

        {!isLoadingHistory && messages.length === 0 ? (
          <div className="flex flex-col items-center justify-center h-full text-slate-400 p-8 text-center animate-in fade-in duration-500">
            <div className="w-16 h-16 bg-white rounded-full shadow-sm flex items-center justify-center mb-4 border border-slate-100 relative">
              <img 
                src="https://i.postimg.cc/B61fmVMV/IDSS_Logo_D1.png" 
                alt="AI Assistant" 
                className="w-10 h-10 object-contain relative z-10" 
              />
              <div className="absolute inset-0 bg-blue-50 rounded-full animate-ping opacity-20"></div>
            </div>
            <h3 className="font-medium text-slate-900 mb-1">AI Pedagogical Assistant</h3>
            <p className="text-sm max-w-xs mx-auto">I'm here to help you refine your lesson plans. Ask me to expand sections, suggest activities, or critique the methodology.</p>
          </div>
        ) : (
          messages.map((msg) => (
            <div 
              key={msg.id} 
              className={`flex w-full ${msg.role === 'user' ? 'justify-end' : 'justify-start'} animate-in slide-in-from-bottom-2 duration-300`}
            >
              <div className={`flex max-w-[90%] gap-3 ${msg.role === 'user' ? 'flex-row-reverse' : 'flex-row'}`}>
                {/* Avatar */}
                <div className={`w-8 h-8 rounded-full flex items-center justify-center flex-shrink-0 mt-1 overflow-hidden border bg-white shadow-sm
                  ${msg.role === 'user' ? 'border-blue-200' : 'border-slate-200'}`}>
                  {msg.role === 'user' ? (
                    <img 
                      src={user?.picture || "https://ui-avatars.com/api/?name=User"} 
                      alt="User" 
                      className="w-full h-full object-cover" 
                    />
                  ) : (
                    <img 
                      src="https://i.postimg.cc/B61fmVMV/IDSS_Logo_D1.png" 
                      alt="AI School Hub" 
                      className="w-full h-full object-contain p-0.5" 
                    />
                  )}
                </div>

                {/* Bubble */}
                <div className={`p-4 rounded-2xl shadow-sm text-sm leading-relaxed overflow-hidden flex flex-col
                  ${msg.role === 'user' 
                    ? 'bg-white border-2 border-blue-100 text-slate-800 rounded-tr-none' 
                    : 'bg-white border border-slate-200 text-slate-700 rounded-tl-none'}`}>

                  {/* Scrollable Content Container */}
                  <div className="max-h-96 overflow-y-auto custom-scrollbar break-words pr-2">
                    <div dangerouslySetInnerHTML={{ __html: msg.text.replace(/\n/g, '<br/>') }} />
                  </div>

                  <div className={`text-[10px] mt-2 pt-2 border-t font-medium
                    ${msg.role === 'user' ? 'text-blue-400 border-blue-50' : 'text-slate-400 border-slate-50'}`}>
                    {msg.role === 'user' ? 'You' : 'AI Assistant'} • {new Date(msg.timestamp).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}
                  </div>
                </div>
              </div>
            </div>
          ))
        )}

        {/* Thinking Indicator Animation */}
        {isSending && (
          <div className="flex w-full justify-start animate-in fade-in duration-300">
            <div className="flex max-w-[80%] gap-3">
              <div className="w-8 h-8 rounded-full bg-white border border-slate-200 flex items-center justify-center flex-shrink-0 mt-1 overflow-hidden">
                <Brain size={18} className="text-primary animate-pulse" />
              </div>
              <div className="bg-white border border-slate-100 p-4 rounded-2xl rounded-tl-none shadow-sm flex flex-col gap-2">
                 <div className="flex items-center gap-2 text-slate-700 font-medium text-sm">
                    <Loader2 size={14} className="animate-spin text-primary" />
                    <span>Analyzing content & thinking...</span>
                 </div>
                 <div className="h-1 w-24 bg-slate-100 rounded-full overflow-hidden">
                    <div className="h-full bg-primary/50 animate-[shimmer_1.5s_infinite] w-full"></div>
                 </div>
              </div>
            </div>
          </div>
        )}
        <div ref={chatEndRef} />
      </div>

      {/* Input Area */}
      <div className="p-4 bg-white border-t border-slate-200 flex-shrink-0 z-10 shadow-sm">
        <form onSubmit={handleSendMessage} className="relative max-w-4xl mx-auto">
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            placeholder="Ask for deep analysis, revisions, or suggestions..."
            className="w-full pl-4 pr-12 py-4 bg-slate-50 border border-slate-200 rounded-xl focus:outline-none focus:ring-2 focus:ring-primary/20 focus:border-primary transition-all text-sm text-slate-800 placeholder-slate-400 shadow-inner"
            disabled={isSending}
          />
          <button 
            type="submit"
            disabled={!input.trim() || isSending}
            className="absolute right-2 top-2.5 p-2 bg-primary text-white rounded-lg hover:bg-blue-600 disabled:opacity-50 disabled:hover:bg-primary transition-colors shadow-sm"
          >
            <Send size={18} />
          </button>
        </form>
        <div className="text-center mt-2">
          <span className="text-[10px] text-slate-400">
            AI can make mistakes. Please review generated content.
          </span>
        </div>
      </div>
    </div>
  );
};

export default ChatPanel;

import React, { useState, useEffect } from 'react';
import { PromptDefinition, NarrativeData, EvaluationData, UserProfile, ContentType } from '../types';
import { streamContent, generateNarrativeAssets, evaluatePedagogy } from '../services/geminiService';
import { saveGeneratedContent, saveTemplate } from '../services/contentService';
import { useToast } from '../context/ToastContext';
import { Download, FileText, FileCode, MessageSquare, BarChart2, Image as ImageIcon, ChevronDown, FileType, File, Save, Check, X, Printer } from 'lucide-react';
import { asBlob } from 'html-docx-js-typescript';

import FormPanel from './editor/FormPanel';
import PreviewPanel from './editor/PreviewPanel';
import ChatPanel from './editor/ChatPanel';

// Declare html2pdf for TypeScript
declare var html2pdf: any;

interface EditorLayoutProps {
  prompt: PromptDefinition;
  user: UserProfile | null;
  initialFormData?: Record<string, string>;
}

const EditorLayout: React.FC<EditorLayoutProps> = ({ prompt, user, initialFormData }) => {
  const { addToast } = useToast();

  // State
  const [formData, setFormData] = useState<Record<string, string>>({});
  const [isGenerating, setIsGenerating] = useState(false);
  const [content, setContent] = useState('');
  const [narrative, setNarrative] = useState<NarrativeData | null>(null);
  const [evaluation, setEvaluation] = useState<EvaluationData | null>(null);
  const [activeView, setActiveView] = useState<'document' | 'narrative' | 'analytics' | 'chat'>('document');
  const [loadingExtras, setLoadingExtras] = useState(false);

  // UI State
  const [showExportMenu, setShowExportMenu] = useState(false);
  const [showSaveTemplateModal, setShowSaveTemplateModal] = useState(false);
  const [templateName, setTemplateName] = useState('');

  // Initialize form defaults
  useEffect(() => {
    const defaults: Record<string, string> = {};
    if (initialFormData) {
        setFormData(initialFormData);
    } else {
        prompt.fields.forEach(f => {
            if (f.defaultValue) defaults[f.key] = f.defaultValue;
        });
        setFormData(defaults);
    }

    // Reset View
    setContent('');
    setNarrative(null);
    setEvaluation(null);
    setActiveView('document');
  }, [prompt, initialFormData, user]);

  const handleInputChange = (key: string, value: string) => {
    setFormData(prev => ({ ...prev, [key]: value }));
  };

  const handleGenerate = async () => {
    setIsGenerating(true);
    setContent('');
    setNarrative(null);
    setEvaluation(null);
    setActiveView('document');

    let userPrompt = `Task: ${prompt.title}\n`;
    Object.entries(formData).forEach(([key, value]) => {
      const fieldLabel = prompt.fields.find(f => f.key === key)?.label || key;
      userPrompt += `${fieldLabel}: ${value}\n`;
    });

    let fullContent = '';

    try {
      addToast('Generating content...', 'info');
      await streamContent(
        'gemini-3-pro-preview', 
        prompt.systemInstruction,
        userPrompt,
        (chunk) => {
          setContent(prev => prev + chunk);
          fullContent += chunk;
        }
      );

      // Auto-save to Firebase if user is logged in
      if (user) {
        try {
          await saveGeneratedContent(user.email, {
             type: prompt.title as unknown as ContentType, 
             title: formData['topic'] || formData['event_name'] || prompt.title,
             content: fullContent,
             metadata: formData
          });
        } catch (e) {
          console.error("Failed to auto-save", e);
        }
      }

      // Generate extras
      generateExtras(fullContent);

    } catch (error) {
      console.error("Generation error:", error);
      addToast("Failed to generate content. Please try again.", 'error');
    } finally {
      setIsGenerating(false);
    }
  };

  const generateExtras = async (text: string) => {
    setLoadingExtras(true);
    try {
      // Parallel execution for efficiency
      const [narrativeResult, evaluationResult] = await Promise.all([
        generateNarrativeAssets(text),
        evaluatePedagogy(text)
      ]);
      setNarrative(narrativeResult);
      setEvaluation(evaluationResult);
    } catch (e) {
      console.error("Error generating extras:", e);
    } finally {
      setLoadingExtras(false);
    }
  };

  // --- SAVE TEMPLATE HANDLER ---
  const handleSaveTemplate = async (e?: React.FormEvent) => {
      if (e) e.preventDefault();

      if (!user) {
          addToast("Please login to save templates", "warning");
          return;
      }
      if (!templateName.trim()) {
          addToast("Please enter a template name", "warning");
          return;
      }

      // NO window.confirm here. The Modal serves as the robust confirmation.
      const id = await saveTemplate(user.email, {
          userId: user.email,
          name: templateName,
          promptId: prompt.id,
          formData: formData
      });

      if (id) {
          addToast("Template saved successfully!", "success");
          setShowSaveTemplateModal(false);
          setTemplateName('');
          // Trigger event to update sidebar
          window.dispatchEvent(new Event('templateSaved'));
      } else {
          addToast("Failed to save template", "error");
      }
  };

  const downloadFile = (blob: Blob, filename: string) => {
      const url = URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = filename;
      a.click();
      URL.revokeObjectURL(url);
  };

  const handlePrint = () => {
    if (!content) {
        addToast("No content to print", "warning");
        return;
    }
    const printWindow = window.open('', '_blank');
    if (printWindow) {
        printWindow.document.write(`
          <!DOCTYPE html>
          <html>
            <head>
              <title>${formData['topic'] || 'Document'} - Print</title>
              <style>
                body { 
                    font-family: 'Helvetica Neue', Helvetica, Arial, sans-serif; 
                    padding: 40px; 
                    max-width: 800px; 
                    margin: 0 auto;
                    line-height: 1.6;
                    color: #1a202c;
                }
                h1 { font-size: 24pt; margin-bottom: 0.5em; border-bottom: 2px solid #e2e8f0; padding-bottom: 10px; }
                h2 { font-size: 18pt; margin-top: 1.5em; margin-bottom: 0.5em; color: #2d3748; }
                h3 { font-size: 14pt; margin-top: 1.2em; margin-bottom: 0.5em; color: #4a5568; }
                p { margin-bottom: 1em; text-align: justify; }
                ul, ol { margin-bottom: 1em; padding-left: 20px; }
                li { margin-bottom: 0.5em; }
                blockquote { border-left: 4px solid #e2e8f0; padding-left: 15px; color: #718096; }
                table { width: 100%; border-collapse: collapse; margin-bottom: 1em; }
                th, td { border: 1px solid #cbd5e0; padding: 8px; text-align: left; }
                th { background-color: #f7fafc; }
              </style>
            </head>
            <body>
              ${content}
              <script>
                window.onload = function() { window.print(); window.close(); }
              </script>
            </body>
          </html>
        `);
        printWindow.document.close();
    }
  };

  // --- EXPORT HANDLERS ---
  const handleExport = async (format: 'pdf' | 'txt' | 'md' | 'docx' | 'html') => {
      if (!content) {
          addToast("No content to export", "warning");
          return;
      }

      const filename = `${formData['topic'] || 'Document'}_${Date.now()}`;

      try {
        if (format === 'pdf') {
            // Find the Quill editor content div
            const element = document.querySelector('.ql-editor') || document.getElementById('document-preview-content');
            if (!element) {
                addToast("Could not find document content", "error");
                return;
            }
            const opt = {
                margin: [0.5, 0.75], // inch
                filename: `${filename}.pdf`,
                image: { type: 'jpeg', quality: 0.98 },
                html2canvas: { scale: 2, useCORS: true },
                jsPDF: { unit: 'in', format: 'letter', orientation: 'portrait' },
                pagebreak: { mode: ['avoid-all', 'css', 'legacy'] }
            };
            html2pdf().set(opt).from(element).save();
            addToast("Downloading PDF...", "success");
        } else if (format === 'txt') {
            const tempDiv = document.createElement("div");
            tempDiv.innerHTML = content.replace(/<br\s*\/?>/gi, '\n').replace(/<\/p>/gi, '\n\n');
            const text = tempDiv.textContent || tempDiv.innerText || "";
            const blob = new Blob([text], { type: 'text/plain' });
            downloadFile(blob, `${filename}.txt`);
            addToast("Downloading Text file...", "success");
        } else if (format === 'md') {
            // Enhanced HTML to Markdown conversion
            let md = content
              .replace(/<h1[^>]*>(.*?)<\/h1>/gim, '# $1\n\n')
              .replace(/<h2[^>]*>(.*?)<\/h2>/gim, '## $1\n\n')
              .replace(/<h3[^>]*>(.*?)<\/h3>/gim, '### $1\n\n')
              .replace(/<strong[^>]*>(.*?)<\/strong>/gim, '**$1**')
              .replace(/<b[^>]*>(.*?)<\/b>/gim, '**$1**')
              .replace(/<em[^>]*>(.*?)<\/em>/gim, '*$1*')
              .replace(/<i[^>]*>(.*?)<\/i>/gim, '*$1*')
              .replace(/<br\s*\/?>/gim, '\n')
              .replace(/<p[^>]*>(.*?)<\/p>/gim, '$1\n\n')
              .replace(/<li[^>]*>(.*?)<\/li>/gim, '- $1\n')
              .replace(/<ul[^>]*>/gim, '')
              .replace(/<\/ul>/gim, '\n')
              .replace(/<ol[^>]*>/gim, '')
              .replace(/<\/ol>/gim, '\n')
              .replace(/&nbsp;/g, ' ')
              .replace(/<[^>]*>/g, ''); 
             const blob = new Blob([md], { type: 'text/markdown' });
             downloadFile(blob, `${filename}.md`);
             addToast("Downloading Markdown...", "success");
        } else if (format === 'docx') {
             // Add styles for Word
             const htmlString = `
                <!DOCTYPE html>
                <html xmlns:o='urn:schemas-microsoft-com:office:office' xmlns:w='urn:schemas-microsoft-com:office:word' xmlns='http://www.w3.org/TR/REC-html40'>
                <head>
                    <meta charset="utf-8">
                    <title>${filename}</title>
                    <style>
                        body { font-family: 'Arial', sans-serif; font-size: 11pt; line-height: 1.15; }
                        h1 { font-size: 16pt; font-weight: bold; margin-bottom: 12pt; }
                        h2 { font-size: 14pt; font-weight: bold; margin-top: 12pt; margin-bottom: 6pt; color: #2E74B5; }
                        h3 { font-size: 12pt; font-weight: bold; margin-top: 10pt; margin-bottom: 4pt; }
                        p { margin-bottom: 8pt; }
                        ul { margin-bottom: 8pt; }
                        li { margin-bottom: 4pt; }
                    </style>
                </head>
                <body>${content}</body>
                </html>`;
             const blob = await asBlob(htmlString);
             if (blob) {
                downloadFile(blob as Blob, `${filename}.docx`);
                addToast("Downloading DOCX...", "success");
             }
        } else if (format === 'html') {
             const blob = new Blob([content], { type: 'text/html' });
             downloadFile(blob, `${filename}.html`);
             addToast("Downloading HTML...", "success");
        }
      } catch (err) {
        console.error("Export error", err);
        addToast("Export failed. Please try again.", "error");
      }
      setShowExportMenu(false);
  };

  // Helper for view switcher button classes
  const getViewButtonClass = (viewName: string) => {
      const isActive = activeView === viewName;
      return `flex items-center gap-2 px-4 py-2 text-sm font-semibold rounded-lg transition-all border
        ${isActive 
            ? 'bg-primary text-white border-primary shadow-sm ring-2 ring-primary/20' 
            : 'bg-white text-slate-500 border-transparent hover:bg-slate-50 hover:text-slate-700'}`;
  };

  return (
    <div className="flex h-full overflow-hidden relative">
      {/* Save Template Modal */}
      {showSaveTemplateModal && (
          <div className="absolute inset-0 z-50 bg-black/60 backdrop-blur-sm flex items-center justify-center p-4">
              <div className="bg-white rounded-xl shadow-2xl p-0 w-full max-w-md animate-in zoom-in-95 duration-200 overflow-hidden">
                  <div className="bg-slate-50 border-b border-slate-100 p-6">
                     <h3 className="text-xl font-bold text-slate-900">Save Configuration</h3>
                     <p className="text-sm text-slate-500 mt-1">
                        Creating a template for <strong>{prompt.title}</strong>
                     </p>
                  </div>

                  <div className="p-6">
                      <p className="text-sm text-slate-600 mb-6 bg-blue-50 p-4 rounded-lg border border-blue-100 text-blue-800">
                          This will save the current <strong>{Object.keys(formData).length} fields</strong> as a reusable template. 
                          You can load it anytime from your profile menu.
                      </p>

                      <form onSubmit={handleSaveTemplate}>
                          <label className="block text-sm font-semibold text-slate-700 mb-2">Template Name</label>
                          <input 
                            type="text" 
                            placeholder="e.g., 'Grade 8 History - Unit 1'" 
                            className="w-full p-3 border border-slate-300 rounded-lg mb-6 outline-none focus:ring-2 focus:ring-primary focus:border-primary transition-all"
                            value={templateName}
                            onChange={e => setTemplateName(e.target.value)}
                            autoFocus
                          />
                          <div className="flex justify-end gap-3">
                              <button 
                                type="button" 
                                onClick={() => setShowSaveTemplateModal(false)} 
                                className="px-5 py-2.5 text-slate-600 hover:bg-slate-100 rounded-lg font-medium transition-colors"
                              >
                                Cancel
                              </button>
                              <button 
                                type="submit" 
                                className="px-5 py-2.5 bg-primary text-white rounded-lg hover:bg-blue-600 font-medium shadow-sm transition-colors flex items-center gap-2"
                              >
                                <Check size={18} />
                                Confirm Save
                              </button>
                          </div>
                      </form>
                  </div>
              </div>
          </div>
      )}

      {/* Left Panel - Form */}
      <FormPanel 
        prompt={prompt} 
        formData={formData} 
        onInputChange={handleInputChange} 
        onGenerate={handleGenerate}
        isGenerating={isGenerating}
        onSaveTemplate={() => setShowSaveTemplateModal(true)}
      />

      {/* Right Panel - Output */}
      <div className="flex-1 flex flex-col bg-slate-100 overflow-hidden relative">
        {/* Toolbar */}
        <div className="bg-white border-b border-slate-200 px-4 py-3 flex items-center justify-between shadow-sm z-10">
          <div className="flex gap-2 p-1 bg-slate-100 rounded-xl">
             <button 
               onClick={() => setActiveView('document')}
               className={getViewButtonClass('document')}
             >
               <FileText size={16} /> Document
             </button>
             <button 
               onClick={() => setActiveView('narrative')}
               className={getViewButtonClass('narrative')}
             >
               <ImageIcon size={16} /> Visuals
             </button>
             <button 
               onClick={() => setActiveView('analytics')}
               className={getViewButtonClass('analytics')}
             >
               <BarChart2 size={16} /> Analytics
             </button>
             <button 
               onClick={() => setActiveView('chat')}
               className={getViewButtonClass('chat')}
             >
               <MessageSquare size={16} /> Chat
             </button>
          </div>

          <div className="relative">
            <button 
                onClick={() => setShowExportMenu(!showExportMenu)}
                className={`flex items-center gap-2 px-4 py-2 text-sm font-semibold rounded-lg transition-colors border
                ${showExportMenu ? 'bg-blue-50 text-primary border-blue-200' : 'bg-white text-slate-600 border-slate-200 hover:bg-slate-50'}`}
            >
                <Download size={16} /> Export <ChevronDown size={14}/>
            </button>
            {showExportMenu && (
                <div className="absolute right-0 top-full mt-2 w-56 bg-white rounded-xl shadow-xl border border-slate-100 overflow-hidden z-50 animate-in slide-in-from-top-2">
                    <button onClick={() => handleExport('pdf')} className="w-full text-left px-4 py-3 hover:bg-slate-50 flex items-center gap-3 text-sm text-slate-700">
                        <FileText size={16} className="text-red-500"/> PDF Document
                    </button>
                    <button onClick={() => handleExport('docx')} className="w-full text-left px-4 py-3 hover:bg-slate-50 flex items-center gap-3 text-sm text-slate-700">
                        <FileText size={16} className="text-blue-600"/> Word Document (.docx)
                    </button>
                    <button onClick={handlePrint} className="w-full text-left px-4 py-3 hover:bg-slate-50 flex items-center gap-3 text-sm text-slate-700 border-t border-slate-100">
                        <Printer size={16} className="text-slate-800"/> Print Document
                    </button>
                    <div className="h-px bg-slate-100 mx-4"></div>
                    <button onClick={() => handleExport('html')} className="w-full text-left px-4 py-3 hover:bg-slate-50 flex items-center gap-3 text-sm text-slate-700">
                        <FileCode size={16} className="text-orange-500"/> HTML File (.html)
                    </button>
                    <button onClick={() => handleExport('txt')} className="w-full text-left px-4 py-3 hover:bg-slate-50 flex items-center gap-3 text-sm text-slate-700">
                        <FileType size={16} className="text-slate-500"/> Plain Text (.txt)
                    </button>
                    <button onClick={() => handleExport('md')} className="w-full text-left px-4 py-3 hover:bg-slate-50 flex items-center gap-3 text-sm text-slate-700">
                        <File size={16} className="text-slate-900"/> Markdown (.md)
                    </button>
                </div>
            )}
          </div>
        </div>

        {/* Content Area */}
        <div className="flex-1 overflow-hidden relative">
           {activeView === 'chat' ? (
             <ChatPanel 
               promptId={prompt.id}
               userEmail={user?.email}
               user={user}
               contentContext={content}
             />
           ) : (
             <div className="h-full overflow-y-auto custom-scrollbar">
                <PreviewPanel 
                  activeView={activeView}
                  content={content}
                  narrative={narrative}
                  evaluation={evaluation}
                  loadingExtras={loadingExtras}
                  isGenerating={isGenerating}
                  prompt={prompt}
                  formData={formData}
                  onContentUpdate={(newContent) => setContent(newContent)}
                />
             </div>
           )}
        </div>
      </div>
    </div>
  );
};

export default EditorLayout;

import React, { useEffect, useRef } from 'react';
import { NarrativeData, EvaluationData, PromptDefinition } from '../../types';
import { Loader2, FileText, Image as ImageIcon, BarChart2, Sparkles, Brain } from 'lucide-react';
import { ResponsiveContainer, RadarChart, PolarGrid, PolarAngleAxis, PolarRadiusAxis, Radar } from 'recharts';

// Declare Quill on window
declare global {
    interface Window {
        Quill: any;
    }
}

interface PreviewPanelProps {
  activeView: 'document' | 'narrative' | 'analytics' | 'chat';
  content: string;
  narrative: NarrativeData | null;
  evaluation: EvaluationData | null;
  loadingExtras: boolean;
  isGenerating: boolean;
  prompt: PromptDefinition;
  formData: Record<string, string>;
  onContentUpdate?: (newContent: string) => void;
}

const PreviewPanel: React.FC<PreviewPanelProps> = ({
  activeView,
  content,
  narrative,
  evaluation,
  loadingExtras,
  isGenerating,
  prompt,
  formData,
  onContentUpdate
}) => {
  const quillRef = useRef<any>(null);
  const editorContainerRef = useRef<HTMLDivElement>(null);
  const isQuillInitialized = useRef(false);

  // Initialize Quill when activeView is 'document' and we are NOT generating
  useEffect(() => {
    if (activeView === 'document' && !isGenerating && editorContainerRef.current) {
        if (!isQuillInitialized.current) {
            // Check if Quill is loaded
            if (window.Quill) {
                quillRef.current = new window.Quill(editorContainerRef.current, {
                    theme: 'snow',
                    modules: {
                        toolbar: [
                            [{ 'header': [1, 2, 3, false] }],
                            ['bold', 'italic', 'underline', 'strike'],
                            [{ 'list': 'ordered'}, { 'list': 'bullet' }],
                            [{ 'color': [] }, { 'background': [] }],
                            [{ 'align': [] }],
                            ['clean']
                        ]
                    }
                });

                // Initialize content
                if (content) {
                    quillRef.current.clipboard.dangerouslyPasteHTML(content);
                }

                // Handle changes
                quillRef.current.on('text-change', () => {
                     if (onContentUpdate && quillRef.current) {
                         onContentUpdate(quillRef.current.root.innerHTML);
                     }
                });

                isQuillInitialized.current = true;
            } else {
                console.error("Quill JS not loaded");
            }
        } else if (quillRef.current && content && quillRef.current.root.innerHTML !== content) {
            // Only update if significantly different and not focused (basic check)
            // Ideally we don't update from props if user is editing, but we do if generation just finished
            // Since we remount on generation start/end, this logic is mostly for switching tabs
            const currentText = quillRef.current.getText();
            // Simple heuristic: if editor is empty but content exists, paste it.
            if (currentText.trim().length === 0 && content.length > 0) {
                 quillRef.current.clipboard.dangerouslyPasteHTML(content);
            }
        }
    }

    // Cleanup logic if needed, but Quill instance is usually persistent for the component lifecycle
    return () => {
        // We don't destroy Quill here to avoid losing state on fast tab switches if we kept it alive,
        // but since we conditionally render the div, we might need to reset.
        if (activeView !== 'document' || isGenerating) {
             isQuillInitialized.current = false;
             quillRef.current = null;
        }
    };
  }, [activeView, isGenerating]); // Removed 'content' from deps to avoid loop

  if (!content && !isGenerating) {
    return (
      <div className="h-full flex flex-col items-center justify-center text-slate-400">
         <div className="w-16 h-16 bg-slate-200 rounded-full flex items-center justify-center mb-4">
           <FileText size={32} className="opacity-50" />
         </div>
         <p>Configure the prompt and click generate to start.</p>
      </div>
    );
  }

  return (
    <div className="h-full flex flex-col relative">

      {/* Prominent Loading Overlay */}
      {isGenerating && !content && (
         <div className="absolute inset-0 z-50 bg-white/90 backdrop-blur-sm flex flex-col items-center justify-center p-8 animate-in fade-in duration-300">
             <div className="relative">
                 <div className="w-20 h-20 bg-primary/10 rounded-full flex items-center justify-center animate-pulse">
                     <Brain size={40} className="text-primary" />
                 </div>
                 <div className="absolute top-0 right-0">
                     <Sparkles size={24} className="text-amber-400 animate-bounce" />
                 </div>
             </div>
             <h3 className="mt-6 text-xl font-bold text-slate-800">Generating Content</h3>
             <p className="text-slate-500 mt-2 max-w-sm text-center">AI is crafting your {prompt.title.toLowerCase()} based on your inputs. This usually takes about 10-20 seconds.</p>
             <div className="mt-8 w-64 h-2 bg-slate-100 rounded-full overflow-hidden">
                 <div className="h-full bg-primary animate-[shimmer_1.5s_infinite] w-full origin-left"></div>
             </div>
         </div>
      )}

      {/* Document View */}
      {activeView === 'document' && (
        <div className="p-8 max-w-4xl mx-auto w-full h-full flex flex-col">
            <div id="document-preview" className="bg-white shadow-lg rounded-xl h-full border border-slate-200 animate-in fade-in duration-500 relative flex flex-col overflow-hidden">

            <div className="p-6 border-b border-slate-200 bg-slate-50">
                <div className="flex justify-between items-end">
                    <div>
                        <h1 className="text-2xl font-bold text-slate-900">{formData.topic || formData.assignment || prompt.title}</h1>
                        <p className="text-slate-500 text-xs mt-1">Generated by AI School Hub • {new Date().toLocaleDateString()}</p>
                    </div>
                    <div className="text-right">
                        <div className="text-xs uppercase tracking-wider font-bold text-slate-400">{prompt.category}</div>
                    </div>
                </div>
            </div>

            {/* Content Area */}
            <div className="flex-1 bg-white relative">
                 {/* 
                    If Generating: Show standard div with streaming content 
                    If Done: Show Quill Editor 
                 */}
                 {isGenerating ? (
                    <div className="p-8 prose prose-slate max-w-none">
                         <div dangerouslySetInnerHTML={{ __html: content.replace(/\n/g, '<br/>') }} />
                         {/* Streaming indicator */}
                         <div className="flex items-center gap-2 text-primary text-sm mt-4 animate-pulse">
                            <Loader2 size={14} className="animate-spin" />
                            <span>Writing...</span>
                         </div>
                    </div>
                 ) : (
                    <div className="h-full flex flex-col">
                        <div ref={editorContainerRef} className="flex-1 text-base"></div>
                    </div>
                 )}
            </div>

            </div>
        </div>
      )}

      {/* Narrative View */}
      {activeView === 'narrative' && (
        <div className="p-8 max-w-4xl mx-auto w-full space-y-6 animate-in slide-in-from-right-4 duration-300">
           {!narrative && !loadingExtras ? (
             <div className="text-center p-12 text-slate-400">Analysis pending...</div>
           ) : (
             <>
              <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
                 <h3 className="text-lg font-bold text-slate-900 mb-4">Executive Summary</h3>
                 {narrative ? <p className="text-slate-700 leading-relaxed">{narrative.summary}</p> : <div className="h-20 bg-slate-100 animate-pulse rounded"></div>}
              </div>

              <div className="grid grid-cols-2 gap-6">
                 <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
                    <h3 className="text-lg font-bold text-slate-900 mb-4">Visual Aid</h3>
                    <div className="aspect-video bg-slate-100 rounded-lg overflow-hidden flex items-center justify-center border border-slate-100">
                       {narrative?.imageUrl ? (
                         <img src={narrative.imageUrl} alt="Generated visual" className="w-full h-full object-cover" />
                       ) : (
                         <div className="flex flex-col items-center text-slate-400">
                           <ImageIcon size={32} className="mb-2 opacity-50"/>
                           <span className="text-xs">{loadingExtras ? 'Generating Visual...' : 'Visual not available'}</span>
                         </div>
                       )}
                    </div>
                 </div>
                 <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
                    <h3 className="text-lg font-bold text-slate-900 mb-4">Key Takeaways</h3>
                    {narrative ? (
                       <ul className="space-y-2">
                         {narrative.keyTakeaways.map((t, i) => (
                           <li key={i} className="flex items-start gap-2 text-sm text-slate-700">
                             <span className="w-5 h-5 rounded-full bg-green-100 text-green-600 flex items-center justify-center text-xs font-bold shrink-0">{i+1}</span>
                             {t}
                           </li>
                         ))}
                       </ul>
                    ) : (
                       <div className="space-y-2">
                          {[1,2,3].map(i => <div key={i} className="h-6 bg-slate-100 animate-pulse rounded w-full"></div>)}
                       </div>
                    )}
                 </div>
              </div>
             </>
           )}
        </div>
      )}

      {/* Analytics View */}
      {activeView === 'analytics' && (
        <div className="p-8 max-w-4xl mx-auto w-full space-y-6 animate-in slide-in-from-right-4 duration-300">
           {!evaluation && !loadingExtras ? (
             <div className="text-center p-12 text-slate-400">Evaluation pending...</div>
           ) : (
             <>
               <div className="grid grid-cols-2 gap-6">
                  <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
                     <h3 className="text-lg font-bold text-slate-900 mb-2">Pedagogical Score</h3>
                     <div className="h-64">
                        {evaluation ? (
                          <ResponsiveContainer width="100%" height="100%">
                            <RadarChart cx="50%" cy="50%" outerRadius="80%" data={[
                              { subject: 'Clarity', A: evaluation.scores.clarity, fullMark: 100 },
                              { subject: 'Relevance', A: evaluation.scores.relevance, fullMark: 100 },
                              { subject: 'Engagement', A: evaluation.scores.engagement, fullMark: 100 },
                              { subject: 'Inclusivity', A: evaluation.scores.inclusivity, fullMark: 100 },
                            ]}>
                              <PolarGrid />
                              <PolarAngleAxis dataKey="subject" tick={{ fill: '#64748b', fontSize: 12 }} />
                              <PolarRadiusAxis angle={30} domain={[0, 100]} />
                              <Radar name="Score" dataKey="A" stroke="#2563eb" fill="#2563eb" fillOpacity={0.4} />
                            </RadarChart>
                          </ResponsiveContainer>
                        ) : <div className="h-full bg-slate-100 animate-pulse rounded"></div>}
                     </div>
                  </div>

                  <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
                     <h3 className="text-lg font-bold text-slate-900 mb-2">Detailed Feedback</h3>
                     <div className="h-64 overflow-y-auto pr-2 custom-scrollbar">
                        {evaluation ? (
                           <>
                             <p className="text-sm text-slate-600 mb-4 italic">"{evaluation.feedback}"</p>
                             <h4 className="font-semibold text-sm text-slate-900 mb-2">Suggestions for Improvement:</h4>
                             <ul className="space-y-2">
                               {evaluation.suggestions.map((s, i) => (
                                  <li key={i} className="text-sm text-slate-700 bg-yellow-50 p-2 rounded border border-yellow-100">
                                    💡 {s}
                                  </li>
                               ))}
                             </ul>
                           </>
                        ) : <div className="space-y-2">{[1,2,3,4].map(i => <div key={i} className="h-4 bg-slate-100 animate-pulse rounded w-full"></div>)}</div>}
                     </div>
                  </div>
               </div>
             </>
           )}
        </div>
      )}
    </div>
  );
};

export default PreviewPanel;

import React, { useState, useEffect } from 'react';
import { PromptDefinition, NarrativeData, EvaluationData, UserProfile, ContentType } from '../types';
import { streamContent, generateNarrativeAssets, evaluatePedagogy } from '../services/geminiService';
import { saveGeneratedContent, saveTemplate } from '../services/contentService';
import { useToast } from '../context/ToastContext';
import { Download, FileText, FileCode, MessageSquare, BarChart2, Image as ImageIcon, ChevronDown, FileType, File, Save, Check, X, Printer } from 'lucide-react';
import { asBlob } from 'html-docx-js-typescript';

import FormPanel from './editor/FormPanel';
import PreviewPanel from './editor/PreviewPanel';
import ChatPanel from './editor/ChatPanel';

// Declare html2pdf for TypeScript
declare var html2pdf: any;

interface EditorLayoutProps {
  prompt: PromptDefinition;
  user: UserProfile | null;
  initialFormData?: Record<string, string>;
}

const EditorLayout: React.FC<EditorLayoutProps> = ({ prompt, user, initialFormData }) => {
  const { addToast } = useToast();

  // State
  const [formData, setFormData] = useState<Record<string, string>>({});
  const [isGenerating, setIsGenerating] = useState(false);
  const [content, setContent] = useState('');
  const [narrative, setNarrative] = useState<NarrativeData | null>(null);
  const [evaluation, setEvaluation] = useState<EvaluationData | null>(null);
  const [activeView, setActiveView] = useState<'document' | 'narrative' | 'analytics' | 'chat'>('document');
  const [loadingExtras, setLoadingExtras] = useState(false);

  // UI State
  const [showExportMenu, setShowExportMenu] = useState(false);
  const [showSaveTemplateModal, setShowSaveTemplateModal] = useState(false);
  const [templateName, setTemplateName] = useState('');

  // Initialize form defaults
  useEffect(() => {
    const defaults: Record<string, string> = {};
    if (initialFormData) {
        setFormData(initialFormData);
    } else {
        prompt.fields.forEach(f => {
            if (f.defaultValue) defaults[f.key] = f.defaultValue;
        });
        setFormData(defaults);
    }

    // Reset View
    setContent('');
    setNarrative(null);
    setEvaluation(null);
    setActiveView('document');
  }, [prompt, initialFormData, user]);

  const handleInputChange = (key: string, value: string) => {
    setFormData(prev => ({ ...prev, [key]: value }));
  };

  const handleGenerate = async () => {
    setIsGenerating(true);
    setContent('');
    setNarrative(null);
    setEvaluation(null);
    setActiveView('document');

    let userPrompt = `Task: ${prompt.title}\n`;
    Object.entries(formData).forEach(([key, value]) => {
      const fieldLabel = prompt.fields.find(f => f.key === key)?.label || key;
      userPrompt += `${fieldLabel}: ${value}\n`;
    });

    let fullContent = '';

    try {
      addToast('Generating content...', 'info');
      await streamContent(
        'gemini-3-pro-preview', 
        prompt.systemInstruction,
        userPrompt,
        (chunk) => {
          setContent(prev => prev + chunk);
          fullContent += chunk;
        }
      );

      // Auto-save to Firebase if user is logged in
      if (user) {
        try {
          await saveGeneratedContent(user.email, {
             type: prompt.title as unknown as ContentType, 
             title: formData['topic'] || formData['event_name'] || prompt.title,
             content: fullContent,
             metadata: formData
          });
        } catch (e) {
          console.error("Failed to auto-save", e);
        }
      }

      // Generate extras
      generateExtras(fullContent);

    } catch (error) {
      console.error("Generation error:", error);
      addToast("Failed to generate content. Please try again.", 'error');
    } finally {
      setIsGenerating(false);
    }
  };

  const generateExtras = async (text: string) => {
    setLoadingExtras(true);
    try {
      // Parallel execution for efficiency
      const [narrativeResult, evaluationResult] = await Promise.all([
        generateNarrativeAssets(text),
        evaluatePedagogy(text)
      ]);
      setNarrative(narrativeResult);
      setEvaluation(evaluationResult);
    } catch (e) {
      console.error("Error generating extras:", e);
    } finally {
      setLoadingExtras(false);
    }
  };

  // --- SAVE TEMPLATE HANDLER ---
  const handleSaveTemplate = async (e?: React.FormEvent) => {
      if (e) e.preventDefault();

      if (!user) {
          addToast("Please login to save templates", "warning");
          return;
      }
      if (!templateName.trim()) {
          addToast("Please enter a template name", "warning");
          return;
      }

      // NO window.confirm here. The Modal serves as the robust confirmation.
      const id = await saveTemplate(user.email, {
          userId: user.email,
          name: templateName,
          promptId: prompt.id,
          formData: formData
      });

      if (id) {
          addToast("Template saved successfully!", "success");
          setShowSaveTemplateModal(false);
          setTemplateName('');
          // Trigger event to update sidebar
          window.dispatchEvent(new Event('templateSaved'));
      } else {
          addToast("Failed to save template", "error");
      }
  };

  const downloadFile = (blob: Blob, filename: string) => {
      const url = URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = filename;
      a.click();
      URL.revokeObjectURL(url);
  };

  const handlePrint = () => {
    if (!content) {
        addToast("No content to print", "warning");
        return;
    }
    const printWindow = window.open('', '_blank');
    if (printWindow) {
        // We inject the Poppins font to ensure consistency with the UI
        printWindow.document.write(`
          <!DOCTYPE html>
          <html>
            <head>
              <title>${formData['topic'] || 'Document'} - Print</title>
              <link href="https://fonts.googleapis.com/css2?family=Poppins:wght@300;400;500;600;700&display=swap" rel="stylesheet">
              <style>
                body { 
                    font-family: 'Poppins', sans-serif; 
                    padding: 40px; 
                    max-width: 800px; 
                    margin: 0 auto;
                    line-height: 1.6;
                    color: #1a202c;
                }
                h1 { font-size: 24pt; margin-bottom: 0.5em; border-bottom: 2px solid #e2e8f0; padding-bottom: 10px; font-weight: 700; }
                h2 { font-size: 18pt; margin-top: 1.5em; margin-bottom: 0.5em; color: #2d3748; font-weight: 600; }
                h3 { font-size: 14pt; margin-top: 1.2em; margin-bottom: 0.5em; color: #4a5568; font-weight: 600; }
                p { margin-bottom: 1em; text-align: justify; }
                ul, ol { margin-bottom: 1em; padding-left: 20px; }
                li { margin-bottom: 0.5em; }
                blockquote { border-left: 4px solid #e2e8f0; padding-left: 15px; color: #718096; font-style: italic; }
                table { width: 100%; border-collapse: collapse; margin-bottom: 1em; }
                th, td { border: 1px solid #cbd5e0; padding: 8px; text-align: left; }
                th { background-color: #f7fafc; font-weight: 600; }

                @media print {
                    body { padding: 0; }
                }
              </style>
            </head>
            <body>
              ${content}
              <script>
                // Wait for fonts to load slightly
                setTimeout(() => {
                    window.print(); 
                    window.close();
                }, 500);
              </script>
            </body>
          </html>
        `);
        printWindow.document.close();
    }
  };

  // --- EXPORT HANDLERS ---
  const handleExport = async (format: 'pdf' | 'txt' | 'md' | 'docx' | 'html') => {
      if (!content) {
          addToast("No content to export", "warning");
          return;
      }

      const filename = `${formData['topic'] || 'Document'}_${Date.now()}`;

      try {
        if (format === 'pdf') {
            // Find the Quill editor content div
            const element = document.querySelector('.ql-editor') || document.getElementById('document-preview-content');
            if (!element) {
                addToast("Could not find document content", "error");
                return;
            }
            const opt = {
                margin: [0.75, 0.75], // inch
                filename: `${filename}.pdf`,
                image: { type: 'jpeg', quality: 0.98 },
                html2canvas: { scale: 2, useCORS: true, logging: false },
                jsPDF: { unit: 'in', format: 'letter', orientation: 'portrait' },
                pagebreak: { mode: ['avoid-all', 'css', 'legacy'] }
            };
            html2pdf().set(opt).from(element).save();
            addToast("Downloading PDF...", "success");
        } else if (format === 'txt') {
            const tempDiv = document.createElement("div");
            tempDiv.innerHTML = content.replace(/<br\s*\/?>/gi, '\n').replace(/<\/p>/gi, '\n\n');
            const text = tempDiv.textContent || tempDiv.innerText || "";
            const blob = new Blob([text], { type: 'text/plain' });
            downloadFile(blob, `${filename}.txt`);
            addToast("Downloading Text file...", "success");
        } else if (format === 'md') {
            // Enhanced HTML to Markdown conversion
            let md = content
              .replace(/<h1[^>]*>(.*?)<\/h1>/gim, '# $1\n\n')
              .replace(/<h2[^>]*>(.*?)<\/h2>/gim, '## $1\n\n')
              .replace(/<h3[^>]*>(.*?)<\/h3>/gim, '### $1\n\n')
              .replace(/<h4[^>]*>(.*?)<\/h4>/gim, '#### $1\n\n')
              .replace(/<strong[^>]*>(.*?)<\/strong>/gim, '**$1**')
              .replace(/<b[^>]*>(.*?)<\/b>/gim, '**$1**')
              .replace(/<em[^>]*>(.*?)<\/em>/gim, '*$1*')
              .replace(/<i[^>]*>(.*?)<\/i>/gim, '*$1*')
              .replace(/<br\s*\/?>/gim, '\n')
              .replace(/<p[^>]*>(.*?)<\/p>/gim, '$1\n\n')
              .replace(/<li[^>]*>(.*?)<\/li>/gim, '- $1\n')
              .replace(/<ul[^>]*>/gim, '')
              .replace(/<\/ul>/gim, '\n')
              .replace(/<ol[^>]*>/gim, '')
              .replace(/<\/ol>/gim, '\n')
              .replace(/&nbsp;/g, ' ')
              .replace(/<blockquote[^>]*>(.*?)<\/blockquote>/gim, '> $1\n\n')
              .replace(/<[^>]*>/g, ''); 
             const blob = new Blob([md], { type: 'text/markdown' });
             downloadFile(blob, `${filename}.md`);
             addToast("Downloading Markdown...", "success");
        } else if (format === 'docx') {
             // Add styles for Word
             const htmlString = `
                <!DOCTYPE html>
                <html xmlns:o='urn:schemas-microsoft-com:office:office' xmlns:w='urn:schemas-microsoft-com:office:word' xmlns='http://www.w3.org/TR/REC-html40'>
                <head>
                    <meta charset="utf-8">
                    <title>${filename}</title>
                    <style>
                        body { font-family: 'Arial', sans-serif; font-size: 11pt; line-height: 1.5; color: #000000; }
                        h1 { font-size: 18pt; font-weight: bold; margin-bottom: 12pt; color: #000000; }
                        h2 { font-size: 16pt; font-weight: bold; margin-top: 14pt; margin-bottom: 6pt; color: #2E74B5; }
                        h3 { font-size: 14pt; font-weight: bold; margin-top: 12pt; margin-bottom: 4pt; color: #4a5568; }
                        p { margin-bottom: 10pt; }
                        ul { margin-bottom: 10pt; list-style-type: disc; }
                        ol { margin-bottom: 10pt; list-style-type: decimal; }
                        li { margin-bottom: 4pt; margin-left: 20px; }
                    </style>
                </head>
                <body>${content}</body>
                </html>`;
             const blob = await asBlob(htmlString);
             if (blob) {
                downloadFile(blob as Blob, `${filename}.docx`);
                addToast("Downloading DOCX...", "success");
             }
        } else if (format === 'html') {
             const blob = new Blob([content], { type: 'text/html' });
             downloadFile(blob, `${filename}.html`);
             addToast("Downloading HTML...", "success");
        }
      } catch (err) {
        console.error("Export error", err);
        addToast("Export failed. Please try again.", "error");
      }
      setShowExportMenu(false);
  };

  // Helper for view switcher button classes
  const getViewButtonClass = (viewName: string) => {
      const isActive = activeView === viewName;
      return `flex items-center gap-2 px-4 py-2 text-sm font-semibold rounded-lg transition-all border
        ${isActive 
            ? 'bg-primary text-white border-primary shadow-sm ring-2 ring-primary/20' 
            : 'bg-white text-slate-500 border-transparent hover:bg-slate-50 hover:text-slate-700'}`;
  };

  return (
    <div className="flex h-full overflow-hidden relative">
      {/* Save Template Modal */}
      {showSaveTemplateModal && (
          <div className="absolute inset-0 z-50 bg-black/60 backdrop-blur-sm flex items-center justify-center p-4">
              <div className="bg-white rounded-xl shadow-2xl p-0 w-full max-w-md animate-in zoom-in-95 duration-200 overflow-hidden">
                  <div className="bg-slate-50 border-b border-slate-100 p-6">
                     <h3 className="text-xl font-bold text-slate-900">Save Configuration</h3>
                     <p className="text-sm text-slate-500 mt-1">
                        Creating a template for <strong>{prompt.title}</strong>
                     </p>
                  </div>

                  <div className="p-6">
                      <p className="text-sm text-slate-600 mb-6 bg-blue-50 p-4 rounded-lg border border-blue-100 text-blue-800">
                          This will save the current <strong>{Object.keys(formData).length} fields</strong> as a reusable template. 
                          You can load it anytime from your profile menu.
                      </p>

                      <form onSubmit={handleSaveTemplate}>
                          <label className="block text-sm font-semibold text-slate-700 mb-2">Template Name</label>
                          <input 
                            type="text" 
                            placeholder="e.g., 'Grade 8 History - Unit 1'" 
                            className="w-full p-3 border border-slate-300 rounded-lg mb-6 outline-none focus:ring-2 focus:ring-primary focus:border-primary transition-all"
                            value={templateName}
                            onChange={e => setTemplateName(e.target.value)}
                            autoFocus
                          />
                          <div className="flex justify-end gap-3">
                              <button 
                                type="button" 
                                onClick={() => setShowSaveTemplateModal(false)} 
                                className="px-5 py-2.5 text-slate-600 hover:bg-slate-100 rounded-lg font-medium transition-colors"
                              >
                                Cancel
                              </button>
                              <button 
                                type="submit" 
                                className="px-5 py-2.5 bg-primary text-white rounded-lg hover:bg-blue-600 font-medium shadow-sm transition-colors flex items-center gap-2"
                              >
                                <Check size={18} />
                                Confirm Save
                              </button>
                          </div>
                      </form>
                  </div>
              </div>
          </div>
      )}

      {/* Left Panel - Form */}
      <FormPanel 
        prompt={prompt} 
        formData={formData} 
        onInputChange={handleInputChange} 
        onGenerate={handleGenerate}
        isGenerating={isGenerating}
        onSaveTemplate={() => setShowSaveTemplateModal(true)}
      />

      {/* Right Panel - Output */}
      <div className="flex-1 flex flex-col bg-slate-100 overflow-hidden relative">
        {/* Toolbar */}
        <div className="bg-white border-b border-slate-200 px-4 py-3 flex items-center justify-between shadow-sm z-10">
          <div className="flex gap-2 p-1 bg-slate-100 rounded-xl">
             <button 
               onClick={() => setActiveView('document')}
               className={getViewButtonClass('document')}
             >
               <FileText size={16} /> Document
             </button>
             <button 
               onClick={() => setActiveView('narrative')}
               className={getViewButtonClass('narrative')}
             >
               <ImageIcon size={16} /> Visuals
             </button>
             <button 
               onClick={() => setActiveView('analytics')}
               className={getViewButtonClass('analytics')}
             >
               <BarChart2 size={16} /> Analytics
             </button>
             <button 
               onClick={() => setActiveView('chat')}
               className={getViewButtonClass('chat')}
             >
               <MessageSquare size={16} /> Chat
             </button>
          </div>

          <div className="relative">
            <button 
                onClick={() => setShowExportMenu(!showExportMenu)}
                className={`flex items-center gap-2 px-4 py-2 text-sm font-semibold rounded-lg transition-colors border
                ${showExportMenu ? 'bg-blue-50 text-primary border-blue-200' : 'bg-white text-slate-600 border-slate-200 hover:bg-slate-50'}`}
            >
                <Download size={16} /> Export <ChevronDown size={14}/>
            </button>
            {showExportMenu && (
                <div className="absolute right-0 top-full mt-2 w-56 bg-white rounded-xl shadow-xl border border-slate-100 overflow-hidden z-50 animate-in slide-in-from-top-2">
                    <button onClick={() => handleExport('pdf')} className="w-full text-left px-4 py-3 hover:bg-slate-50 flex items-center gap-3 text-sm text-slate-700">
                        <FileText size={16} className="text-red-500"/> PDF Document
                    </button>
                    <button onClick={() => handleExport('docx')} className="w-full text-left px-4 py-3 hover:bg-slate-50 flex items-center gap-3 text-sm text-slate-700">
                        <FileText size={16} className="text-blue-600"/> Word Document (.docx)
                    </button>
                    <button onClick={handlePrint} className="w-full text-left px-4 py-3 hover:bg-slate-50 flex items-center gap-3 text-sm text-slate-700 border-t border-slate-100">
                        <Printer size={16} className="text-slate-800"/> Print Document
                    </button>
                    <div className="h-px bg-slate-100 mx-4"></div>
                    <button onClick={() => handleExport('html')} className="w-full text-left px-4 py-3 hover:bg-slate-50 flex items-center gap-3 text-sm text-slate-700">
                        <FileCode size={16} className="text-orange-500"/> HTML File (.html)
                    </button>
                    <button onClick={() => handleExport('txt')} className="w-full text-left px-4 py-3 hover:bg-slate-50 flex items-center gap-3 text-sm text-slate-700">
                        <FileType size={16} className="text-slate-500"/> Plain Text (.txt)
                    </button>
                    <button onClick={() => handleExport('md')} className="w-full text-left px-4 py-3 hover:bg-slate-50 flex items-center gap-3 text-sm text-slate-700">
                        <File size={16} className="text-slate-900"/> Markdown (.md)
                    </button>
                </div>
            )}
          </div>
        </div>

        {/* Content Area */}
        <div className="flex-1 overflow-hidden relative">
           {activeView === 'chat' ? (
             <ChatPanel 
               promptId={prompt.id}
               userEmail={user?.email}
               user={user}
               contentContext={content}
             />
           ) : (
             <div className="h-full overflow-y-auto custom-scrollbar">
                <PreviewPanel 
                  activeView={activeView}
                  content={content}
                  narrative={narrative}
                  evaluation={evaluation}
                  loadingExtras={loadingExtras}
                  isGenerating={isGenerating}
                  prompt={prompt}
                  formData={formData}
                  onContentUpdate={(newContent) => setContent(newContent)}
                />
             </div>
           )}
        </div>
      </div>
    </div>
  );
};

export default EditorLayout;
